import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Frequency {
  WEEKLY = 'WEEKLY',
  MONTHLY = 'MONTHLY',
}

export enum XitiqueStatus {
  PLANNING = 'PLANNING',
  ACTIVE = 'ACTIVE',
  COMPLETED = 'COMPLETED',
}

export interface Participant {
  id: string;
  name: string;
  payoutDate?: string; // ISO Date string
  received: boolean;
  order: number;
}

export interface Xitique {
  id: string;
  name: string;
  amount: number; // Contribution per person
  frequency: Frequency;
  startDate: string; // ISO Date string
  participants: Participant[];
  status: XitiqueStatus;
  createdAt: number;
}

export interface SimulationResult {
  cycleDurationText: string;
  totalPot: number;
  totalContributionPerPerson: number;
  payouts: { date: string; amount: number; recipientIndex: number }[];
}

export const APP_NAME = "XitiqueFlow";

export const SAMPLE_NAMES = [
  "Maria", "Joao", "Ana", "Carlos", "Isabel", "Pedro", "Sofia", "Luiz"
];

export const AI_PROMPT_PREFIX = `
You are a financial assistant for a Rotating Savings and Credit Association (Xitique/ROSCA). 
Analyze the fairness of the following group setup. 
The users are non-technical. Keep the language extremely simple, encouraging, and clear.
Do not use formulas. Focus on the benefits of saving together versus the slight advantage of receiving money early.
`;

import { Frequency } from '../types';

export const formatDate = (dateStr: string): string => {
  if (!dateStr) return '';
  return new Date(dateStr).toLocaleDateString('en-GB', {
    day: 'numeric',
    month: 'short',
    year: 'numeric'
  });
};

export const addPeriod = (dateStr: string, frequency: Frequency, count: number): string => {
  const date = new Date(dateStr);
  if (frequency === Frequency.WEEKLY) {
    date.setDate(date.getDate() + (7 * count));
  } else {
    date.setMonth(date.getMonth() + count);
  }
  return date.toISOString();
};

export const calculateDuration = (frequency: Frequency, count: number): string => {
  if (frequency === Frequency.WEEKLY) {
    return `${count} Weeks`;
  }
  return `${count} Months`;
};

import { Xitique, XitiqueStatus } from '../types';

const STORAGE_KEY = 'xitique_app_data_v1';

export const getXitiques = (): Xitique[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const saveXitique = (xitique: Xitique): void => {
  const current = getXitiques();
  const existingIndex = current.findIndex(x => x.id === xitique.id);

  if (existingIndex >= 0) {
    current[existingIndex] = xitique;
  } else {
    current.push(xitique);
  }

  localStorage.setItem(STORAGE_KEY, JSON.stringify(current));
};

export const deleteXitique = (id: string): void => {
  const current = getXitiques();
  const filtered = current.filter(x => x.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
};

export const createNewXitique = (partial: Partial<Xitique>): Xitique => {
  return {
    id: crypto.randomUUID(),
    name: partial.name || 'My New Group',
    amount: partial.amount || 100,
    frequency: partial.frequency || 'MONTHLY' as any,
    startDate: partial.startDate || new Date().toISOString(),
    participants: partial.participants || [],
    status: XitiqueStatus.PLANNING,
    createdAt: Date.now(),
  };
};

import { GoogleGenAI } from "@google/genai";
import { Xitique } from '../types';
import { AI_PROMPT_PREFIX } from '../constants';
import { formatDate } from './dateUtils';

// Initialize Gemini
// NOTE: In a real production app, you would proxy this through a backend to protect the key.
// For this frontend-only demo, we rely on the env var.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFairness = async (xitique: Xitique): Promise<string> => {
  if (!process.env.API_KEY) {
    return "AI Analysis unavailable: API Key not configured.";
  }

  const participantList = xitique.participants.map((p, i) => 
    `${i + 1}. ${p.name} receives on ${p.payoutDate ? formatDate(p.payoutDate) : 'TBD'}`
  ).join('\n');

  const prompt = `
    ${AI_PROMPT_PREFIX}

    Group Name: ${xitique.name}
    Contribution: ${xitique.amount} per person.
    Frequency: ${xitique.frequency}
    Total Participants: ${xitique.participants.length}

    Rotation Schedule:
    ${participantList}

    Please provide:
    1. A simplified "Fairness Rating" (Good, Moderate, Needs Attention).
    2. A friendly explanation of who benefits slightly more (early receivers) vs who is the "hero saver" (late receivers).
    3. One tip for managing this group smoothly.

    Keep it short (under 150 words). Format with clear headers or bullet points.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Could not generate analysis.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Unable to connect to the smart assistant. Please check your internet connection.";
  }
};

