  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.MONTHLY);

  const [data, setData] = useState<any[]>([]);

  useEffect(() => {
    // Generate simulation data
    const totalPot = amount * participants;
    const newData = Array.from({ length: participants }).map((_, i) => {
      return {
        name: `Person ${i + 1}`,
        contributed: amount * (i + 1), // How much they have put in by the time they get paid (approx logic for illustration)
        received: totalPot,
        profit: totalPot - (amount * participants), // Zero sum game usually
        netValue: totalPot - (amount * (i + 1)) // Positive means early advantage
      };
    });
    setData(newData);
