import React, { useState, useEffect } from 'react';
import { Frequency, Xitique } from '../types';
import { createNewXitique, saveXitique } from '../services/storage';
import { addPeriod, formatDate } from '../services/dateUtils';
import { ChevronRight, ChevronLeft, Check, UserPlus, Trash2, ArrowUp, ArrowDown, Calendar, GripVertical } from 'lucide-react';

interface WizardProps {
  onComplete: () => void;
  onCancel: () => void;
}

const Wizard: React.FC<WizardProps> = ({ onComplete, onCancel }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.MONTHLY);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [participantNames, setParticipantNames] = useState<string[]>(['', '']);

  // This state holds the names after Step 2, allowing re-ordering
  const [orderedParticipants, setOrderedParticipants] = useState<string[]>([]);

  // Initialize order when entering step 3
  useEffect(() => {
    if (step === 3 && orderedParticipants.length === 0) {
        setOrderedParticipants(participantNames.filter(n => n.trim() !== ''));
    }
  }, [step, participantNames]);

  const handleAddParticipant = () => {
    setParticipantNames([...participantNames, '']);
  };

  const handleRemoveParticipant = (index: number) => {
    const newNames = [...participantNames];
    newNames.splice(index, 1);
    setParticipantNames(newNames);
  };

  const handleNameChange = (index: number, val: string) => {
    const newNames = [...participantNames];
    newNames[index] = val;
    setParticipantNames(newNames);
  };

  const moveParticipant = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...orderedParticipants];
    if (direction === 'up' && index > 0) {
        [newOrder[index], newOrder[index - 1]] = [newOrder[index - 1], newOrder[index]];
    } else if (direction === 'down' && index < newOrder.length - 1) {
        [newOrder[index], newOrder[index + 1]] = [newOrder[index + 1], newOrder[index]];
    }
    setOrderedParticipants(newOrder);
  };

  const handleFinish = () => {
    // Generate Final Participants from the ORDERED list
    const participants = orderedParticipants.map((pName, index) => ({
      id: crypto.randomUUID(),
      name: pName,
      received: false,
      order: index + 1,
      // Payout #1 is at Start Date + 1 Period usually, or Start Date if pre-funded.
      // We will assume "Get money at the meeting".
      payoutDate: addPeriod(startDate, frequency, index)
    }));

    const newXitique = createNewXitique({
      name,
      amount,
      frequency,
      startDate: new Date(startDate).toISOString(),
      participants
    });

    saveXitique(newXitique);
    onComplete();
  };

  const totalSteps = 4;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-3xl mx-auto border border-slate-200">
      {/* Header */}
      <div className="bg-slate-900 p-8 text-white flex justify-between items-center relative overflow-hidden">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold tracking-tight">Create New Xitique</h2>
          <p className="text-slate-400 text-sm mt-1">Configure your savings circle</p>
        </div>

        {/* Progress Dots */}
        <div className="flex space-x-3 relative z-10">
          {[1, 2, 3, 4].map((s) => (
             <div 
                key={s} 
                className={`transition-all duration-500 ${step === s ? 'w-8 bg-emerald-400' : step > s ? 'w-3 bg-emerald-800' : 'w-3 bg-slate-700'} h-3 rounded-full`} 
             />
          ))}
        </div>

        {/* Abstract Deco */}
        <div className="absolute right-0 top-0 h-full w-1/3 bg-emerald-500/10 transform -skew-x-12 translate-x-10"></div>
      </div>

      <div className="p-8 md:p-10">

        {/* STEP 1: BASICS */}
        {step === 1 && (
          <div className="space-y-6 animate-fade-in">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Group Details</h3>

            <div className="group">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Group Name</label>
              <input 
                type="text" 
                value={name} 
                onChange={(e) => setName(e.target.value)}
                placeholder="e.g., Office Savings 2024"
                className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                autoFocus
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Contribution Amount</label>
                <div className="relative">
                  <span className="absolute left-4 top-4 text-slate-400 font-bold">$</span>
                  <input 
                    type="number" 
                    value={amount} 
                    onChange={(e) => setAmount(Number(e.target.value))}
                    className="w-full p-4 pl-8 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all font-mono"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Frequency</label>
                <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 rounded-xl">
                  <button 
                    onClick={() => setFrequency(Frequency.WEEKLY)}
                    className={`py-3 rounded-lg text-sm font-medium transition-all ${frequency === Frequency.WEEKLY ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    Weekly
                  </button>
                  <button 
                    onClick={() => setFrequency(Frequency.MONTHLY)}
                    className={`py-3 rounded-lg text-sm font-medium transition-all ${frequency === Frequency.MONTHLY ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                    Monthly
                  </button>
                </div>
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-700 mb-2">First Contribution Date</label>
              <input 
                type="date" 
                value={startDate} 
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
              />
            </div>
          </div>
        )}

        {/* STEP 2: PARTICIPANTS */}
        {step === 2 && (
          <div className="space-y-6 animate-fade-in">
            <h3 className="text-xl font-bold text-slate-800">Add Participants</h3>
            <p className="text-sm text-slate-500 mb-4 bg-blue-50 p-3 rounded-lg border border-blue-100">
               Enter the names of everyone joining. Don't worry about the order yet; you can arrange the schedule in the next step.
            </p>

            <div className="max-h-[400px] overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {participantNames.map((pName, idx) => (
                <div key={idx} className="flex items-center gap-3 animate-fade-in">
                  <span className="bg-slate-200 text-slate-600 w-10 h-10 flex items-center justify-center rounded-xl text-sm font-bold shadow-sm">
                    {idx + 1}
                  </span>
                  <input
                    type="text"
                    placeholder={`Name of person ${idx + 1}`}
                    value={pName}
                    onChange={(e) => handleNameChange(idx, e.target.value)}
                    className="flex-1 p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    autoFocus={idx === participantNames.length - 1 && idx > 0}
                  />
                  {participantNames.length > 2 && (
                    <button onClick={() => handleRemoveParticipant(idx)} className="text-slate-300 hover:text-red-500 transition-colors p-2">
                      <Trash2 size={20} />
                    </button>
                  )}
                </div>
              ))}
            </div>

            <button 
              onClick={handleAddParticipant}
              className="w-full py-4 border-2 border-dashed border-slate-300 rounded-xl flex items-center justify-center text-slate-500 font-medium hover:border-emerald-500 hover:text-emerald-600 hover:bg-emerald-50 transition-all mt-4"
            >
              <UserPlus size={18} className="mr-2" /> Add another person
            </button>
          </div>
        )}

        {/* STEP 3: ORDERING (ALGORITHM OF JUSTICE) */}
        {step === 3 && (
            <div className="space-y-6 animate-fade-in">
                <div className="flex items-center justify-between">
                    <h3 className="text-xl font-bold text-slate-800">Rotation Schedule</h3>
                    <div className="bg-emerald-100 text-emerald-800 text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">
                        Manual Order
                    </div>
                </div>

                <p className="text-sm text-slate-600 mb-4">
                    Arrange the participants. Move people UP or DOWN to assign them to specific dates based on their requests.
                </p>

                <div className="space-y-3">
                    {orderedParticipants.map((pName, idx) => {
                        const calculatedDate = addPeriod(startDate, frequency, idx);
                        const isLast = idx === orderedParticipants.length - 1;
                        const isFirst = idx === 0;

                        return (
                            <div key={idx} className="flex items-center gap-4 bg-white border border-slate-200 p-3 rounded-xl shadow-sm hover:border-emerald-300 transition-all group">
                                <div className="text-slate-300 cursor-grab">
                                    <GripVertical size={20} />
                                </div>

                                <div className="flex-1">
                                    <div className="flex justify-between items-center">
                                        <span className="font-bold text-slate-800 text-lg">{pName}</span>
                                        <div className="flex items-center text-sm text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg">
                                            <Calendar size={14} className="mr-2" />
                                            {formatDate(calculatedDate)}
                                        </div>
                                    </div>
                                    <div className="text-xs text-slate-400 mt-1">Position {idx + 1}</div>
                                </div>

                                <div className="flex flex-col gap-1">
                                    <button 
                                        onClick={() => moveParticipant(idx, 'up')}
                                        disabled={isFirst}
                                        className={`p-1 rounded hover:bg-slate-100 ${isFirst ? 'text-slate-200' : 'text-slate-500 hover:text-emerald-600'}`}
                                    >
                                        <ArrowUp size={18} />
                                    </button>
                                    <button 
                                        onClick={() => moveParticipant(idx, 'down')}
                                        disabled={isLast}
                                        className={`p-1 rounded hover:bg-slate-100 ${isLast ? 'text-slate-200' : 'text-slate-500 hover:text-emerald-600'}`}
                                    >
                                        <ArrowDown size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}

        {/* STEP 4: REVIEW */}
        {step === 4 && (
          <div className="animate-fade-in text-center py-4">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-lg shadow-emerald-100">
              <Check size={40} strokeWidth={3} />
            </div>
            <h3 className="text-3xl font-bold text-slate-900 mb-3">All Set!</h3>
            <p className="text-slate-500 mb-8 max-w-md mx-auto leading-relaxed">
              You are launching <strong>{name}</strong> with <strong>{participantNames.filter(n => n).length} members</strong>.
              <br />
              Each payout will be <strong className="text-emerald-600 text-xl">${amount * participantNames.filter(n => n).length}</strong>.
            </p>

            <div className="bg-slate-50 border border-slate-200 p-6 rounded-2xl text-left text-sm text-slate-600 mb-6">
               <h4 className="font-bold text-slate-800 mb-2">Summary:</h4>
               <ul className="space-y-2">
                 <li className="flex justify-between"><span>First Payout:</span> <span className="font-medium text-slate-800">{orderedParticipants[0]} ({formatDate(startDate)})</span></li>
                 <li className="flex justify-between"><span>Last Payout:</span> <span className="font-medium text-slate-800">{orderedParticipants[orderedParticipants.length-1]}</span></li>
               </ul>
            </div>
          </div>
        )}

        {/* Footer Actions */}
        <div className="flex justify-between mt-10 pt-6 border-t border-slate-100">
          {step === 1 ? (
            <button onClick={onCancel} className="text-slate-400 font-semibold hover:text-slate-600 px-4">
              Cancel
            </button>
          ) : (
            <button onClick={() => setStep(step - 1)} className="flex items-center text-slate-500 font-semibold hover:text-slate-800 px-4">
              <ChevronLeft size={20} className="mr-1" /> Back
            </button>
          )}

          {step < 4 ? (
            <button 
              onClick={() => {
                if(step === 1 && !name) { alert("Please enter a name"); return; }
                if(step === 2) {
                     // Filter empty names
                     const valid = participantNames.filter(n => n.trim() !== '');
                     if (valid.length < 2) { alert("Need at least 2 people."); return; }
                     // Reset ordered list if names changed
                     if (valid.length !== orderedParticipants.length) {
                         setOrderedParticipants(valid);
                     }
                }
                setStep(step + 1)
              }} 
              className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-3 rounded-xl font-semibold flex items-center shadow-xl shadow-slate-200 transition-all transform hover:-translate-y-0.5"
            >
              Next Step <ChevronRight size={20} className="ml-1" />
            </button>
          ) : (
            <button 
              onClick={handleFinish} 
              className="bg-emerald-500 hover:bg-emerald-600 text-white px-10 py-3 rounded-xl font-bold flex items-center shadow-xl shadow-emerald-200 transition-all transform hover:-translate-y-0.5"
            >
              Launch Xitique
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Wizard;

