                    <p className="text-slate-500 text-sm">{t('sim.analysis_desc')}</p>
                </div>
            </div>

            <div className="grid md:grid-cols-4 gap-6">
                <div className="md:col-span-3 h-64 w-full bg-slate-50 rounded-2xl p-4 border border-slate-100">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={data} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                    <XAxis dataKey="name" tick={{fontSize: 12}} axisLine={false} tickLine={false} />
                    <YAxis hide />
                    <Tooltip 
                        cursor={{fill: '#f1f5f9'}}
                        contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', backgroundColor: '#1e293b', color: '#fff' }}
                        formatter={(value: number) => [`${Math.abs(Math.round(value))} units`, value > 0 ? t('sim.advantage') : t('sim.disadvantage')]}
                    />
                    <ReferenceLine y={0} stroke="#94a3b8" />
                    <Bar dataKey="netValue" radius={[4, 4, 4, 4]}>
                        {data.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.netValue > 0 ? '#10b981' : '#f43f5e'} />
                        ))}
                    </Bar>
                    </BarChart>
                </ResponsiveContainer>
                </div>

