                            <button 
                                onClick={() => handleDeposit(stick)}
                                disabled={progress >= 100}
                                className="w-full py-3 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-200 disabled:text-slate-400 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95"
                            >
                                <ArrowUpRight size={18} /> {t('ind.deposit')} {stick.amount}
                            </button>
                        </div>
                    );
                })}
            </div>
        )}
    </div>
