export interface Notification {
  id: string;
  title: string;
  message: string;
  date: string;
  read: boolean;
  type: 'info' | 'warning' | 'success';
}

import { Xitique, Notification, XitiqueType, XitiqueStatus } from '../types';
import { getXitiques } from './storage';

const NOTIF_STORAGE_KEY = 'xitique_notifications_v1';

export const getNotifications = (): Notification[] => {
  const data = localStorage.getItem(NOTIF_STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const saveNotifications = (notifications: Notification[]): void => {
  localStorage.setItem(NOTIF_STORAGE_KEY, JSON.stringify(notifications));
};

export const markNotificationRead = (id: string): Notification[] => {
  const current = getNotifications();
  const updated = current.map(n => n.id === id ? { ...n, read: true } : n);
  saveNotifications(updated);
  return updated;
};

// Logic to check active xitiques and generate notifications based on dates
export const checkAndGenerateNotifications = (): Notification[] => {
  const xitiques = getXitiques();
  const existingNotifications = getNotifications();
  const newNotifications: Notification[] = [...existingNotifications];
  const today = new Date();

  // Helper to see if notification already exists for this specific event
  const exists = (idPrefix: string) => existingNotifications.some(n => n.id === idPrefix);

  xitiques.forEach(x => {
    if (x.status === XitiqueStatus.ACTIVE || x.status === XitiqueStatus.PLANNING) {

      // GROUP LOGIC
      if (x.type === XitiqueType.GROUP) {
        x.participants.forEach(p => {
          if (!p.received && p.payoutDate) {
            const pDate = new Date(p.payoutDate);
            const diffTime = pDate.getTime() - today.getTime();
            const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

            // Reminder 3 days before
            if (diffDays <= 3 && diffDays >= 0) {
              const notifId = `payout-${x.id}-${p.id}-${p.payoutDate}`;
              if (!exists(notifId)) {
                newNotifications.unshift({
                  id: notifId,
                  title: 'Payout Upcoming',
                  message: `${p.name} is due to receive ${x.amount * x.participants.length} MT in ${diffDays === 0 ? 'today' : diffDays + ' days'}.`,
                  date: new Date().toISOString(),
                  read: false,
                  type: 'info'
                });
              }
            }

            // Reminder if Overdue
            if (diffDays < 0) {
               const notifId = `overdue-${x.id}-${p.id}-${p.payoutDate}`;
               if (!exists(notifId)) {
                newNotifications.unshift({
                  id: notifId,
                  title: 'Payout Overdue',
                  message: `${p.name} was supposed to receive on ${new Date(p.payoutDate).toLocaleDateString()}. Please check status.`,
                  date: new Date().toISOString(),
                  read: false,
                  type: 'warning'
                });
               }
            }
          }
        });
      }

      // PERSONAL LOGIC
      if (x.type === XitiqueType.INDIVIDUAL) {
         // Simple reminder logic: If last interaction was long ago?
         // For MVP, let's just simulate a "Keep going" message if created > 7 days ago and not complete
         const created = new Date(x.createdAt || Date.now());
         const diffCreated = Math.ceil((today.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));

         if (diffCreated > 0 && diffCreated % 7 === 0 && (x.currentBalance || 0) < (x.targetAmount || 1)) {
             const notifId = `ind-reminder-${x.id}-${diffCreated}`;
             if (!exists(notifId)) {
                 newNotifications.unshift({
                     id: notifId,
                     title: 'Savings Goal Reminder',
                     message: `Don't forget to contribute to your goal '${x.name}'. You are doing great!`,
                     date: new Date().toISOString(),
                     read: false,
                     type: 'success'
                 });
             }
         }
      }
    }
  });

  saveNotifications(newNotifications);
  return newNotifications;
};

