                    const remaining = Math.max(0, target - balance);
                    const estimatedPeriods = Math.ceil(remaining / stick.amount);
                    const isExpanded = expandedId === stick.id;

                    return (
                        <div 
                            key={stick.id} 
                            onClick={() => setExpandedId(isExpanded ? null : stick.id)}
                            className={`bg-white rounded-2xl p-6 border transition-all cursor-pointer ${isExpanded ? 'border-purple-300 shadow-xl ring-2 ring-purple-50' : 'border-slate-200 shadow-sm hover:shadow-lg'}`}
