                                        {getMethodIcon(stick.method)}
                                    </div>
                                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">
                                        {getFrequencyLabel(stick.frequency)} • {formatCurrency(stick.amount)}
                                    </p>
                                </div>
                                <button onClick={(e) => handleDelete(stick.id, e)} className="text-slate-300 hover:text-red-500 transition-colors">
                                    <Trash size={18} />
                                </button>
                            </div>

                            <div className="mb-6">
                                <div className="flex justify-between text-xs font-semibold text-slate-500 mb-2">
                                    <span className="flex items-center gap-1"><Target size={12}/> {formatCurrency(target)}</span>
                                    <span className={remaining === 0 ? "text-emerald-500" : "text-slate-900"}>{remaining === 0 ? "Completed!" : `${t('ind.remaining')}: ${formatCurrency(remaining)}`}</span>
                                </div>
                                <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
                                    <div 
                                        className="bg-purple-500 h-3 rounded-full transition-all duration-1000 ease-out" 
                                        style={{ width: `${progress}%` }}
                                    />
                                </div>
                            </div>

                            <div className="flex items-center justify-between mb-6 bg-slate-50 p-4 rounded-xl border border-slate-100">
                                <div>
                                    <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mb-1">{t('ind.balance')}</p>
                                    <p className="text-2xl font-bold text-slate-900">{formatCurrency(balance)}</p>
                                </div>
                                {estimatedPeriods > 0 && (
                                    <div className="text-right">
                                        <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mb-1">{t('ind.estimate')}</p>
                                        <p className="text-sm font-bold text-slate-700 bg-white px-2 py-1 rounded shadow-sm inline-block">
                                            {estimatedPeriods} {stick.frequency === 'DAILY' ? t('ind.days') : stick.frequency === 'WEEKLY' ? t('ind.weeks') : t('ind.months')}
