import { analyzeFairness } from '../services/geminiService';
import { saveXitique, deleteXitique } from '../services/storage';
import { Sparkles, Calendar, DollarSign, Users, ArrowLeft, Trash, CheckCircle2, Clock, Pencil, X, Check, History } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  xitique: Xitique;
  onBack: () => void;
  onDelete: () => void;
}

const XitiqueDetail: React.FC<Props> = ({ xitique, onBack, onDelete }) => {
  const { t } = useLanguage();
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [activeTab, setActiveTab] = useState<'schedule' | 'analysis' | 'history'>('schedule');

  // Edit State
  const [isEditing, setIsEditing] = useState(false);
  const [newAmount, setNewAmount] = useState(xitique.amount);

  useEffect(() => {
    setNewAmount(xitique.amount);
  }, [xitique.amount]);

  const potSize = xitique.amount * xitique.participants.length;

  const handleRunAnalysis = async () => {
    setLoadingAi(true);
    const result = await analyzeFairness(xitique);
    setAiAnalysis(result);
    setLoadingAi(false);
  };

  const markReceived = (participantId: string) => {
    const participant = xitique.participants.find(p => p.id === participantId);
    if (!participant) return;

    // Toggle logic
    const willReceive = !participant.received;

    let updatedTx = [...(xitique.transactions || [])];

    if (willReceive) {
        // Create Transaction
        updatedTx.unshift({
            id: crypto.randomUUID(),
            type: TransactionType.PAYOUT,
            amount: potSize,
            date: new Date().toISOString(),
            description: `${t('ind.type_payout')}: ${participant.name}`
        });
    } else {
        // Optional: Remove transaction if unmarked? For audit safety, usually we wouldn't delete, 
        // but for a simple toggle in this UI, removing the *last* payout for this person makes sense to keep state in sync.
        // For simplicity in this demo, we just add records. Real apps might void/refund.
    }

    const updatedParticipants = xitique.participants.map(p => 
      p.id === participantId ? { ...p, received: willReceive } : p
    );

    const updatedXitique = { 
        ...xitique, 
        participants: updatedParticipants,
        transactions: updatedTx
    };

    saveXitique(updatedXitique);
    xitique.participants = updatedParticipants; 
    xitique.transactions = updatedTx;
    // Force re-render handled by parent typically, but here we rely on local mutation + React key changes if we were rigorous.
    // We toggle a dummy state to force render since props are mutated.
    setAiAnalysis(null); 
  };

  const saveContributionChange = () => {
    if (newAmount <= 0) return;
    const updatedXitique = { ...xitique, amount: newAmount };
    saveXitique(updatedXitique);
    xitique.amount = newAmount; // Update local ref
    setIsEditing(false);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 transition-colors font-medium">
          <ArrowLeft size={20} className="mr-2" /> {t('detail.back')}
        </button>
        <div className="flex gap-2">
            <button 
                onClick={() => {
                    if(confirm(t('detail.confirm_delete'))) onDelete();
                }}
                className="text-red-500 hover:bg-red-50 px-4 py-2 rounded-xl flex items-center text-sm font-medium transition-colors"
            >
                <Trash size={18} className="mr-2" /> {t('detail.delete')}
            </button>
        </div>
      </div>

      <div className="bg-slate-900 text-white rounded-3xl p-8 shadow-xl relative overflow-hidden">
        <div className="absolute right-0 top-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

        <div className="relative z-10">
            <div className="flex items-center gap-3 mb-2">
                <span className="bg-emerald-500 text-slate-900 text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">{xitique.frequency === 'WEEKLY' ? t('wiz.weekly') : t('wiz.monthly')}</span>
            </div>
            <h1 className="text-4xl font-bold mb-6 tracking-tight">{xitique.name}</h1>

            <div className="flex flex-wrap gap-4">
                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10 relative group">
                    <div className="bg-emerald-400/20 p-2 rounded-lg">
                        <DollarSign size={20} className="text-emerald-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold flex items-center gap-2">
                            {t('detail.contribution_per_person')}
                            <button onClick={() => setIsEditing(true)} className="hover:text-white transition-colors"><Pencil size={12} /></button>
                        </div>
                        <div className="text-xl font-bold">{formatCurrency(xitique.amount)}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-emerald-400/20 p-2 rounded-lg">
                        <DollarSign size={20} className="text-emerald-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.total_payout')}</div>
                        <div className="text-xl font-bold">{formatCurrency(potSize)}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-blue-400/20 p-2 rounded-lg">
                        <Users size={20} className="text-blue-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.members')}</div>
                        <div className="text-xl font-bold">{xitique.participants.length}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-purple-400/20 p-2 rounded-lg">
                        <Calendar size={20} className="text-purple-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.start_date')}</div>
                        <div className="text-xl font-bold">{formatDate(xitique.startDate)}</div>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {isEditing && (
          <div className="bg-white border-2 border-emerald-100 p-6 rounded-2xl shadow-lg flex flex-col md:flex-row items-center gap-4 animate-fade-in">
              <div className="flex-1">
                  <h3 className="font-bold text-slate-900 mb-1">{t('detail.edit_contribution')}</h3>
                  <p className="text-xs text-slate-500">This will update the total payout for all future turns.</p>
              </div>
              <div className="flex items-center gap-2">
                  <div className="relative">
                      <span className="absolute left-3 top-3 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                      <input 
                        type="number" 
                        value={newAmount} 
                        onChange={(e) => setNewAmount(Number(e.target.value))}
                        className="pl-10 p-2 border border-slate-300 rounded-lg w-32 font-bold text-slate-900 focus:ring-2 focus:ring-emerald-500 outline-none"
                      />
                  </div>
                  <button onClick={saveContributionChange} className="bg-emerald-500 hover:bg-emerald-600 text-white p-2.5 rounded-lg transition-colors">
                      <Check size={18} />
                  </button>
                  <button onClick={() => { setIsEditing(false); setNewAmount(xitique.amount); }} className="bg-slate-100 hover:bg-slate-200 text-slate-500 p-2.5 rounded-lg transition-colors">
                      <X size={18} />
                  </button>
              </div>
          </div>
      )}

      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('schedule')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'schedule' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          {t('detail.tab_schedule')}
          {activeTab === 'schedule' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-500 rounded-t-full" />}
        </button>
        <button 
          onClick={() => setActiveTab('history')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'history' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <span className="flex items-center gap-2">
            <History size={16} /> {t('detail.tab_history')}
          </span>
          {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-500 rounded-t-full" />}
        </button>
        <button 
          onClick={() => setActiveTab('analysis')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'analysis' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <span className="flex items-center gap-2">
            <Sparkles size={16} className="text-purple-500" /> {t('detail.tab_analysis')}
          </span>
          {activeTab === 'analysis' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-purple-500 rounded-t-full" />}
        </button>
      </div>

      {activeTab === 'schedule' && (
        <div className="space-y-4">
          <div className="grid gap-4">
            {xitique.participants.map((p, idx) => (
              <div 
                key={p.id} 
                className={`flex flex-col md:flex-row md:items-center justify-between p-5 rounded-2xl border transition-all ${
                  p.received 
                    ? 'bg-emerald-50/50 border-emerald-100' 
                    : 'bg-white border-slate-200 hover:border-emerald-200 shadow-sm'
                }`}
              >
                <div className="flex items-center gap-5 mb-4 md:mb-0">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-xl shadow-sm ${
                    p.received ? 'bg-emerald-200 text-emerald-800' : 'bg-slate-100 text-slate-600'
                  }`}>
                    {idx + 1}
                  </div>
                  <div>
                    <h3 className={`font-bold text-lg ${p.received ? 'text-emerald-900' : 'text-slate-900'}`}>
                      {p.name}
                    </h3>
                    <div className="flex items-center gap-2 text-sm text-slate-500 mt-1">
                        <Clock size={14} />
                        {p.payoutDate ? formatDate(p.payoutDate) : t('detail.date_tbd')}
                    </div>
                  </div>
                </div>

                <div className="flex items-center justify-end">
                   <button 
                      onClick={() => markReceived(p.id)}
                      className={`flex items-center gap-3 px-5 py-2.5 rounded-xl font-medium transition-all ${
                          p.received 
                          ? 'bg-emerald-500 text-white shadow-emerald-200 shadow-lg' 
                          : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                      }`}
                   >
                      {p.received ? (
                          <>
                            <CheckCircle2 size={18} /> {t('detail.paid_out')}
                          </>
                      ) : (
                          <>
                            <div className="w-4 h-4 rounded-full border-2 border-slate-400"></div> {t('detail.mark_paid')}
                          </>
                      )}
                   </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            {!xitique.transactions || xitique.transactions.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                    <History size={48} className="mx-auto mb-4 opacity-20" />
                    <p>{t('detail.empty_history')}</p>
                </div>
            ) : (
                <div className="divide-y divide-slate-100">
                    {xitique.transactions.map((tx) => (
                        <div key={tx.id} className="p-4 flex justify-between items-center hover:bg-slate-50">
                            <div>
                                <div className="font-bold text-slate-800 text-sm">{tx.description || t('ind.type_payout')}</div>
                                <div className="text-xs text-slate-500">{new Date(tx.date).toLocaleDateString()} {new Date(tx.date).toLocaleTimeString()}</div>
                            </div>
                            <div className="text-right">
                                <div className="font-bold text-emerald-600">{formatCurrency(tx.amount)}</div>
                                <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">{tx.type}</div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm min-h-[400px]">
          {!aiAnalysis ? (
            <div className="text-center py-16">
              <div className="w-20 h-20 bg-purple-50 text-purple-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <Sparkles size={40} />
              </div>
              <h3 className="text-2xl font-bold text-slate-900 mb-3">{t('detail.ai_title')}</h3>
              <p className="text-slate-500 max-w-md mx-auto mb-8">
                {t('detail.ai_desc')}
              </p>
              <button 
                onClick={handleRunAnalysis}
                disabled={loadingAi}
                className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-4 rounded-xl font-bold shadow-xl shadow-slate-200 transition-all disabled:opacity-50 flex items-center gap-2 mx-auto"
              >
                {loadingAi ? (
                    <>{t('detail.ai_running')}</>
                ) : (
                    <>
                        <Sparkles size={18} /> {t('detail.ai_btn')}
                    </>
                )}
              </button>
            </div>
          ) : (
             <div className="prose prose-slate max-w-none">
                <div className="flex items-center gap-4 mb-8 pb-6 border-b border-slate-100">
                   <div className="bg-purple-100 p-3 rounded-xl text-purple-700">
                      <Sparkles size={28} />
                   </div>
                   <div>
                       <h3 className="text-xl font-bold text-slate-900 m-0">{t('detail.ai_report')}</h3>
                       <p className="text-slate-500 text-sm">{t('detail.ai_generated')}</p>
                   </div>
                </div>
                <div className="whitespace-pre-wrap text-slate-700 leading-relaxed bg-slate-50 p-8 rounded-2xl border border-slate-200 font-medium">
                  {aiAnalysis}
                </div>
                <button 
                  onClick={() => setAiAnalysis(null)}
                  className="mt-8 text-slate-500 font-semibold hover:text-slate-900 text-sm flex items-center gap-2"
                >
                  <ArrowLeft size={16} /> {t('detail.ai_reset')}
                </button>
             </div>
          )}
        </div>
      )}
    </div>
  );
};

export default XitiqueDetail;

import React, { useState, useEffect } from 'react';
import { Xitique } from '../types';
import { getXitiques } from '../services/storage';
import { formatCurrency } from '../services/formatUtils';
import { PlusCircle, Calendar, ChevronRight, Wallet } from 'lucide-react';
import { formatDate } from '../services/dateUtils';
import { useLanguage } from '../contexts/LanguageContext';

interface DashboardProps {
  onCreate: () => void;
  onSelect: (xitique: Xitique) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onCreate, onSelect }) => {
  const [xitiques, setXitiques] = useState<Xitique[]>([]);
  const { t } = useLanguage();

  useEffect(() => {
    setXitiques(getXitiques());
  }, []);

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight">{t('dash.title')}</h1>
          <p className="text-slate-500 mt-1">{t('dash.subtitle')}</p>
        </div>
        <button 
          onClick={onCreate}
          className="bg-emerald-500 hover:bg-emerald-600 text-white px-4 py-2 rounded-xl font-medium shadow-lg shadow-emerald-200 transition-all flex items-center md:hidden"
        >
          <PlusCircle size={20} />
        </button>
      </div>

      {xitiques.length === 0 ? (
        <div className="text-center py-24 bg-white rounded-3xl border border-dashed border-slate-300 shadow-sm">
          <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-6 text-emerald-400">
            <Wallet size={40} />
          </div>
          <h3 className="text-xl font-bold text-slate-800 mb-2">{t('dash.no_active')}</h3>
          <p className="text-slate-500 mb-8 max-w-sm mx-auto">{t('dash.start_new')}</p>
          <button 
            onClick={onCreate}
            className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-4 rounded-xl font-bold shadow-xl shadow-slate-200 transition-all inline-flex items-center transform hover:-translate-y-1"
          >
            <PlusCircle size={20} className="mr-2" /> {t('dash.btn_init')}
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {xitiques.map((x) => {
            const progress = (x.participants.filter(p => p.received).length / x.participants.length) * 100;
            return (
              <div 
                key={x.id} 
                onClick={() => onSelect(x)}
                className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-xl hover:border-emerald-200 transition-all duration-300 cursor-pointer group relative overflow-hidden"
              >
                {/* Decoration */}
                <div className="absolute top-0 right-0 w-24 h-24 bg-slate-50 rounded-bl-full -mr-4 -mt-4 z-0 group-hover:bg-emerald-50 transition-colors"></div>

                <div className="relative z-10">
                    <div className="flex justify-between items-start mb-6">
                    <div className="h-12 w-12 bg-slate-900 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-md">
                        {x.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="bg-slate-100 text-slate-600 text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-wide group-hover:bg-emerald-100 group-hover:text-emerald-700 transition-colors">
                        {x.frequency === 'WEEKLY' ? t('wiz.weekly') : t('wiz.monthly')}
                    </div>
                    </div>

                    <h3 className="text-xl font-bold text-slate-900 mb-1 group-hover:text-emerald-600 transition-colors truncate">
                    {x.name}
                    </h3>
                    <p className="text-slate-400 text-sm mb-6 flex items-center">
                    <Calendar size={14} className="mr-1" /> {t('dash.started')} {formatDate(x.startDate)}
                    </p>

                    <div className="mb-6">
                        <div className="flex justify-between text-xs font-semibold text-slate-500 mb-2">
                            <span>{t('dash.progress')}</span>
                            <span className="text-slate-900">{Math.round(progress)}%</span>
                        </div>
                        <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                            <div 
                            className="bg-emerald-500 h-2 rounded-full transition-all duration-1000 ease-out" 
                            style={{ width: `${progress}%` }}
                            />
                        </div>
                    </div>

                    <div className="flex justify-between items-center pt-4 border-t border-slate-100">
                    <div className="text-lg font-bold text-slate-900">
                        {formatCurrency(x.amount * x.participants.length)} <span className="text-slate-400 font-medium text-xs">/ {t('dash.payout')}</span>
                    </div>
                    <div className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center group-hover:bg-emerald-500 group-hover:text-white transition-colors">
                        <ChevronRight size={16} />
                    </div>
                    </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Frequency } from '../types';
import { calculateDuration } from '../services/dateUtils';
import { formatCurrency } from '../services/formatUtils';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell } from 'recharts';
import { Users, DollarSign, RefreshCw, TrendingUp } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const Simulation: React.FC = () => {
  const { t, language } = useLanguage();
  const [participants, setParticipants] = useState(5);
  const [amount, setAmount] = useState(1000);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.MONTHLY);

  const [data, setData] = useState<any[]>([]);

  useEffect(() => {
    // Generate simulation data
    const totalPot = amount * participants;
    const newData = Array.from({ length: participants }).map((_, i) => {
      // Simulate inflation impact (simple logic: money later is worth less)
      const advantage = (participants - 1 - (2 * i)) * (amount * 0.05); 

      return {
        name: `${i + 1}`,
        netValue: advantage
      };
    });
    setData(newData);
  }, [participants, amount, frequency]);

  const totalPot = amount * participants;
  const cycleTime = calculateDuration(frequency, participants, language);
  const totalContribution = amount * participants;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-200">
        <div className="flex items-center gap-4 mb-6">
          <div className="bg-slate-900 p-3 rounded-xl text-emerald-400">
            <RefreshCw size={28} />
          </div>
          <div>
             <h2 className="text-2xl font-bold text-slate-900">{t('sim.title')}</h2>
             <p className="text-slate-500">{t('sim.subtitle')}</p>
          </div>
        </div>

        {/* Controls */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
            <label className="block text-sm font-bold text-slate-700 mb-3 flex items-center gap-2">
              <Users size={16} /> {t('sim.num_people')}
            </label>
            <div className="flex items-center justify-between mb-2">
                <span className="text-slate-400 text-xs">Min: 2</span>
                <span className="text-2xl font-bold text-slate-900">{participants}</span>
                <span className="text-slate-400 text-xs">Max: 20</span>
            </div>
            <input 
              type="range" 
              min="2" 
              max="20" 
              value={participants} 
              onChange={(e) => setParticipants(parseInt(e.target.value))}
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500"
            />
          </div>

          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
            <label className="block text-sm font-bold text-slate-700 mb-3 flex items-center gap-2">
              <DollarSign size={16} /> {t('sim.contribution')}
            </label>
            <div className="flex items-center justify-between mb-2">
                <span className="text-slate-400 text-xs">100</span>
                <span className="text-2xl font-bold text-slate-900">{amount}</span>
                <span className="text-slate-400 text-xs">5000</span>
            </div>
            <input 
              type="range" 
              min="100" 
              max="5000" 
              step="100"
              value={amount} 
              onChange={(e) => setAmount(parseInt(e.target.value))}
              className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-500"
            />
          </div>

          <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
             <label className="block text-sm font-bold text-slate-700 mb-3">{t('sim.frequency')}</label>
             <div className="flex bg-white rounded-xl border border-slate-200 p-1.5 shadow-sm">
                <button 
                  onClick={() => setFrequency(Frequency.WEEKLY)}
                  className={`flex-1 py-2 rounded-lg text-sm font-bold transition-colors ${frequency === Frequency.WEEKLY ? 'bg-slate-900 text-emerald-400' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                  {t('wiz.weekly')}
                </button>
                <button 
                  onClick={() => setFrequency(Frequency.MONTHLY)}
                  className={`flex-1 py-2 rounded-lg text-sm font-bold transition-colors ${frequency === Frequency.MONTHLY ? 'bg-slate-900 text-emerald-400' : 'text-slate-500 hover:bg-slate-50'}`}
                >
                  {t('wiz.monthly')}
                </button>
             </div>
          </div>
        </div>

        {/* Results */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
          <div className="p-6 bg-emerald-50 rounded-2xl border border-emerald-100 text-center">
            <div className="text-xs text-emerald-800 font-bold uppercase tracking-wider mb-1">{t('sim.pot')}</div>
            <div className="text-4xl font-bold text-emerald-600">{formatCurrency(totalPot)}</div>
          </div>
          <div className="p-6 bg-blue-50 rounded-2xl border border-blue-100 text-center">
            <div className="text-xs text-blue-800 font-bold uppercase tracking-wider mb-1">{t('sim.cycle')}</div>
            <div className="text-4xl font-bold text-blue-600">{cycleTime}</div>
          </div>
          <div className="p-6 bg-slate-100 rounded-2xl border border-slate-200 text-center">
            <div className="text-xs text-slate-600 font-bold uppercase tracking-wider mb-1">{t('sim.investment')}</div>
            <div className="text-4xl font-bold text-slate-700">{formatCurrency(totalContribution)}</div>
          </div>
        </div>

        {/* Visual Logic */}
        <div className="mt-8 border-t border-slate-100 pt-8">
            <div className="flex items-center gap-3 mb-6">
                <div className="bg-rose-100 p-2 rounded-lg text-rose-500">
                    <TrendingUp size={20} />
                </div>
                <div>
                    <h3 className="text-lg font-bold text-slate-900">{t('sim.analysis_title')}</h3>
                    <p className="text-slate-500 text-sm">{t('sim.analysis_desc')}</p>
                </div>
            </div>

            <div className="grid md:grid-cols-4 gap-6">
                <div className="md:col-span-3 h-64 w-full bg-slate-50 rounded-2xl p-4 border border-slate-100">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={data} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                    <XAxis dataKey="name" tick={{fontSize: 12}} axisLine={false} tickLine={false} />
                    <YAxis hide />
                    <Tooltip 
                        cursor={{fill: '#f1f5f9'}}
                        contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', backgroundColor: '#1e293b', color: '#fff' }}
                        formatter={(value: number) => [`${Math.abs(Math.round(value))} units`, value > 0 ? t('sim.advantage') : t('sim.disadvantage')]}
                    />
                    <ReferenceLine y={0} stroke="#94a3b8" />
                    <Bar dataKey="netValue" radius={[4, 4, 4, 4]}>
                        {data.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.netValue > 0 ? '#10b981' : '#f43f5e'} />
                        ))}
                    </Bar>
                    </BarChart>
                </ResponsiveContainer>
                </div>

                <div className="space-y-4">
                    <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
                        <h4 className="font-bold text-emerald-800 text-sm mb-1">{t('sim.green_bars')}</h4>
                        <p className="text-xs text-emerald-700 leading-relaxed">
                            {t('sim.green_desc')}
                        </p>
                    </div>
                    <div className="bg-rose-50 p-4 rounded-xl border border-rose-100">
                        <h4 className="font-bold text-rose-800 text-sm mb-1">{t('sim.red_bars')}</h4>
                        <p className="text-xs text-rose-700 leading-relaxed">
                            {t('sim.red_desc')}
                        </p>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

