import React, { useState, useEffect } from 'react';
import { Lightbulb, Info, ShieldAlert } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

type TipContext = 'group' | 'individual' | 'withdrawal' | 'general';

interface FinancialTipProps {
  context: TipContext;
}

const FinancialTip: React.FC<FinancialTipProps> = ({ context }) => {
  const { t } = useLanguage();
  const [tipKey, setTipKey] = useState<string>('');

  useEffect(() => {
    // Select a random tip key based on context
    const tips = {
      group: ['tip.group_1', 'tip.group_2'],
      individual: ['tip.ind_1', 'tip.ind_2'],
      withdrawal: ['tip.with_1', 'tip.with_2'],
      general: ['tip.group_1', 'tip.ind_1']
    };

    const availableTips = tips[context] || tips.general;
    const randomTip = availableTips[Math.floor(Math.random() * availableTips.length)];
    setTipKey(randomTip);
  }, [context]);

  const isWarning = context === 'withdrawal';

  return (
    <div className={`rounded-xl p-4 border flex items-start gap-3 transition-all animate-fade-in ${
      isWarning 
        ? 'bg-amber-50 border-amber-200 text-amber-900' 
        : 'bg-indigo-50 border-indigo-100 text-indigo-900'
    }`}>
      <div className={`p-2 rounded-lg ${isWarning ? 'bg-amber-100' : 'bg-indigo-100'}`}>
        {isWarning ? <ShieldAlert size={20} className="text-amber-600" /> : <Lightbulb size={20} className="text-indigo-600" />}
      </div>
      <div>
        <h4 className="text-xs font-bold uppercase tracking-wide opacity-70 mb-1">
          {t('tip.did_you_know')}
        </h4>
        <p className="text-sm font-medium leading-relaxed">
          {t(tipKey)}
        </p>
      </div>
    </div>
  );
};

export default FinancialTip;

import React, { useState, useEffect } from 'react';
import { Xitique, XitiqueType, Frequency, PaymentMethod, TransactionType } from '../types';
import { getXitiques, saveXitique, createNewXitique, deleteXitique } from '../services/storage';
import { formatCurrency } from '../services/formatUtils';
import { formatDate } from '../services/dateUtils';
import { PiggyBank, Plus, Smartphone, Banknote, Trash, ArrowUpRight, ArrowDownLeft, TrendingUp, X, Clock, Target, CalendarClock } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import FinancialTip from './FinancialTip';

const IndividualDashboard: React.FC = () => {
  const { t } = useLanguage();
  const [sticks, setSticks] = useState<Xitique[]>([]);
  const [isCreating, setIsCreating] = useState(false);
  const [withdrawStick, setWithdrawStick] = useState<Xitique | null>(null);
  const [withdrawAmount, setWithdrawAmount] = useState<number>(0);

  // Form State
  const [name, setName] = useState('');
  const [targetAmount, setTargetAmount] = useState(5000);
  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.DAILY);
  const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.MPESA);

  // Expanded View State
  const [expandedId, setExpandedId] = useState<string | null>(null);

  useEffect(() => {
    loadSticks();
  }, []);

  const loadSticks = () => {
    const all = getXitiques();
    setSticks(all.filter(x => x.type === XitiqueType.INDIVIDUAL));
  };

  const handleCreate = () => {
    if (!name) return alert(t('wiz.alert_name'));

    const newStick = createNewXitique({
      name,
      type: XitiqueType.INDIVIDUAL,
      targetAmount,
      amount,
      currentBalance: 0,
      frequency,
      method,
      startDate: new Date().toISOString(),
      participants: [] // No participants for individual
    });

    saveXitique(newStick);
    setIsCreating(false);
    loadSticks();
    // Reset form
    setName('');
    setTargetAmount(5000);
    setAmount(100);
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm(t('detail.confirm_delete'))) {
      deleteXitique(id);
      loadSticks();
    }
  };

  const handleDeposit = (stick: Xitique, e?: React.MouseEvent) => {
    if(e) e.stopPropagation();

    const newTx = {
        id: crypto.randomUUID(),
        type: TransactionType.DEPOSIT,
        amount: stick.amount,
        date: new Date().toISOString(),
        description: t('ind.type_deposit')
    };

    const updated = {
      ...stick,
      currentBalance: (stick.currentBalance || 0) + stick.amount,
      transactions: [newTx, ...(stick.transactions || [])]
    };
    saveXitique(updated);
    loadSticks();
  };

  const handleWithdraw = () => {
    if(!withdrawStick) return;

    if (withdrawAmount > (withdrawStick.currentBalance || 0)) {
        alert("Amount exceeds balance");
        return;
    }

    const newTx = {
        id: crypto.randomUUID(),
        type: TransactionType.WITHDRAWAL,
        amount: withdrawAmount,
        date: new Date().toISOString(),
        description: t('ind.type_withdrawal')
    };

    const updated = {
        ...withdrawStick,
        currentBalance: (withdrawStick.currentBalance || 0) - withdrawAmount,
        transactions: [newTx, ...(withdrawStick.transactions || [])]
    };

    saveXitique(updated);
    setWithdrawStick(null);
    loadSticks();
  };

  const getMethodIcon = (m?: PaymentMethod) => {
    switch (m) {
      case PaymentMethod.MPESA: return <span className="bg-red-100 text-red-700 border border-red-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> M-Pesa</span>;
      case PaymentMethod.EMOLA: return <span className="bg-orange-100 text-orange-700 border border-orange-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> e-Mola</span>;
      default: return <span className="bg-emerald-100 text-emerald-700 border border-emerald-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Banknote size={12}/> Cash</span>;
    }
  };

  const getFrequencyLabel = (f: Frequency) => {
    switch (f) {
      case Frequency.DAILY: return t('ind.daily');
      case Frequency.WEEKLY: return t('ind.weekly');
      default: return t('ind.monthly');
    }
  };

  // Timeline Calculation Logic
  const getProjectedDate = (stick: Xitique) => {
    if (!stick.currentBalance || stick.currentBalance <= 0) return null;
    if (!stick.transactions || stick.transactions.length === 0) return null;

    const start = new Date(stick.createdAt);
    const now = new Date();
    const daysSinceStart = Math.max(1, Math.floor((now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)));

    // Average daily saving rate
    const ratePerDay = stick.currentBalance / daysSinceStart;

    if (ratePerDay <= 0) return null;

    const remaining = (stick.targetAmount || 0) - stick.currentBalance;
    if (remaining <= 0) return new Date(); // Done

    const daysLeft = Math.ceil(remaining / ratePerDay);
    const projectedDate = new Date();
    projectedDate.setDate(projectedDate.getDate() + daysLeft);

    return projectedDate;
  };

  if (isCreating) {
    return (
      <div className="max-w-xl mx-auto bg-white p-8 rounded-3xl shadow-xl border border-slate-200 animate-fade-in my-8">
        <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <PiggyBank className="text-purple-500" /> {t('ind.create_btn')}
            </h2>
            <button onClick={() => setIsCreating(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 text-slate-500">
                <X size={20} />
            </button>
        </div>

        <div className="space-y-6">
            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_name')}</label>
                <input 
                    type="text" 
                    value={name} 
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Ex: Novo Telefone"
                    className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_target')}</label>
                    <div className="relative">
                        <span className="absolute left-3 top-3.5 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                        <input 
                            type="number" 
                            value={targetAmount} 
                            onChange={(e) => setTargetAmount(Number(e.target.value))}
                            className="w-full p-3 pl-10 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none font-mono"
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_contribution')}</label>
                    <div className="relative">
                        <span className="absolute left-3 top-3.5 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                        <input 
                            type="number" 
                            value={amount} 
                            onChange={(e) => setAmount(Number(e.target.value))}
                            className="w-full p-3 pl-10 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none font-mono"
                        />
                    </div>
                </div>
            </div>

            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_freq')}</label>
                <div className="grid grid-cols-3 gap-2">
                    {[Frequency.DAILY, Frequency.WEEKLY, Frequency.MONTHLY].map(f => (
                        <button
                            key={f}
                            onClick={() => setFrequency(f)}
                            className={`py-2 px-1 rounded-lg text-xs font-bold border transition-all ${
                                frequency === f 
                                ? 'bg-purple-600 text-white border-purple-600' 
                                : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                            }`}
                        >
                            {getFrequencyLabel(f)}
                        </button>
                    ))}
                </div>
            </div>

            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_method')}</label>
                <div className="grid grid-cols-3 gap-2">
                    {[
                        { id: PaymentMethod.MPESA, label: 'M-Pesa', icon: Smartphone },
                        { id: PaymentMethod.EMOLA, label: 'e-Mola', icon: Smartphone },
                        { id: PaymentMethod.CASH, label: 'Cash', icon: Banknote },
                    ].map(m => (
                        <button
                            key={m.id}
                            onClick={() => setMethod(m.id)}
                            className={`py-3 px-2 rounded-xl text-xs font-bold border flex flex-col items-center gap-1 transition-all ${
                                method === m.id
                                ? 'bg-slate-900 text-white border-slate-900' 
                                : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                            }`}
                        >
                            <m.icon size={16} />
                            {m.label}
                        </button>
                    ))}
                </div>
            </div>

            <button 
                onClick={handleCreate}
                className="w-full py-4 bg-purple-600 hover:bg-purple-700 text-white font-bold rounded-xl shadow-lg shadow-purple-200 transition-all mt-4"
            >
                {t('ind.create_btn')}
            </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fade-in pb-12">
        {/* Withdrawal Modal */}
        {withdrawStick && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-3xl p-6 max-w-sm w-full shadow-2xl animate-fade-in">
                    <h3 className="text-xl font-bold text-slate-900 mb-2">{t('ind.withdraw_modal_title')}</h3>
                    <p className="text-slate-500 text-sm mb-4">{t('ind.withdraw_modal_desc')}</p>

                    <div className="mb-4">
                      <FinancialTip context="withdrawal" />
                    </div>

                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-4">
                        <div className="text-xs text-slate-400 font-bold uppercase">{t('ind.balance')}</div>
                        <div className="text-xl font-bold text-slate-900">{formatCurrency(withdrawStick.currentBalance || 0)}</div>
                    </div>

                    <label className="block text-xs font-bold text-slate-700 mb-1">Amount</label>
                    <input 
                        type="number" 
                        value={withdrawAmount} 
                        max={withdrawStick.currentBalance}
                        onChange={(e) => setWithdrawAmount(Number(e.target.value))}
                        className="w-full p-3 border border-slate-300 rounded-xl mb-6 font-bold text-lg"
                    />

                    <div className="flex gap-2">
                        <button 
                            onClick={() => setWithdrawStick(null)}
                            className="flex-1 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold rounded-xl"
                        >
                            {t('ind.withdraw_cancel')}
                        </button>
                        <button 
                            onClick={handleWithdraw}
                            className="flex-1 py-3 bg-slate-900 hover:bg-slate-800 text-white font-bold rounded-xl"
                        >
                            {t('ind.withdraw_confirm')}
                        </button>
                    </div>
                </div>
            </div>
        )}

        <div className="flex justify-between items-center">
            <div>
                <h1 className="text-3xl font-bold text-slate-900 tracking-tight">{t('ind.title')}</h1>
                <p className="text-slate-500 mt-1">{t('ind.subtitle')}</p>
            </div>
            <button 
                onClick={() => setIsCreating(true)}
                className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 md:px-6 md:py-3 rounded-xl font-bold shadow-lg shadow-purple-200 transition-all flex items-center gap-2"
            >
                <Plus size={20} /> <span className="hidden md:inline">{t('ind.create_btn')}</span>
            </button>
        </div>

        {sticks.length > 0 && (
           <FinancialTip context="individual" />
        )}

        {sticks.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-300 shadow-sm">
                <div className="w-20 h-20 bg-purple-50 rounded-full flex items-center justify-center mx-auto mb-6 text-purple-400">
                    <PiggyBank size={40} />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">{t('ind.no_active')}</h3>
                <p className="text-slate-500 mb-8 max-w-sm mx-auto">{t('ind.start_desc')}</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {sticks.map(stick => {
                    const balance = stick.currentBalance || 0;
                    const target = stick.targetAmount || 1;
                    const progress = Math.min(100, (balance / target) * 100);
                    const remaining = Math.max(0, target - balance);
                    const estimatedPeriods = Math.ceil(remaining / stick.amount);
                    const isExpanded = expandedId === stick.id;
                    const projectedDate = getProjectedDate(stick);

                    return (
                        <div 
                            key={stick.id} 
                            onClick={() => setExpandedId(isExpanded ? null : stick.id)}
                            className={`bg-white rounded-2xl p-6 border transition-all cursor-pointer ${isExpanded ? 'border-purple-300 shadow-xl ring-2 ring-purple-50 col-span-1 md:col-span-2' : 'border-slate-200 shadow-sm hover:shadow-lg'}`}
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <h3 className="text-lg font-bold text-slate-900">{stick.name}</h3>
                                        {getMethodIcon(stick.method)}
                                    </div>
                                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">
                                        {getFrequencyLabel(stick.frequency)} • {formatCurrency(stick.amount)}
                                    </p>
                                </div>
                                <button onClick={(e) => handleDelete(stick.id, e)} className="text-slate-300 hover:text-red-500 transition-colors">
                                    <Trash size={18} />
                                </button>
                            </div>

                            <div className="mb-6">
                                <div className="flex justify-between text-xs font-semibold text-slate-500 mb-2">
                                    <span className="flex items-center gap-1"><Target size={12}/> {formatCurrency(target)}</span>
                                    <span className={remaining === 0 ? "text-emerald-500" : "text-slate-900"}>{remaining === 0 ? "Completed!" : `${t('ind.remaining')}: ${formatCurrency(remaining)}`}</span>
                                </div>
                                <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
                                    <div 
                                        className="bg-purple-500 h-3 rounded-full transition-all duration-1000 ease-out" 
                                        style={{ width: `${progress}%` }}
                                    />
                                </div>
                            </div>

                            <div className="flex items-center justify-between mb-6 bg-slate-50 p-4 rounded-xl border border-slate-100">
                                <div>
                                    <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mb-1">{t('ind.balance')}</p>
                                    <p className="text-2xl font-bold text-slate-900">{formatCurrency(balance)}</p>
                                </div>
                                {estimatedPeriods > 0 && (
                                    <div className="text-right">
                                        <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mb-1">{t('ind.estimate')}</p>
                                        <p className="text-sm font-bold text-slate-700 bg-white px-2 py-1 rounded shadow-sm inline-block">
                                            {estimatedPeriods} {stick.frequency === 'DAILY' ? t('ind.days') : stick.frequency === 'WEEKLY' ? t('ind.weeks') : t('ind.months')}
                                        </p>
                                    </div>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-3 mb-4">
                                <button 
                                    onClick={(e) => handleDeposit(stick, e)}
                                    disabled={progress >= 100}
                                    className="py-3 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-200 disabled:text-slate-400 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 text-sm"
                                >
                                    <ArrowUpRight size={16} /> {t('ind.deposit')}
                                </button>
                                <button 
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        setWithdrawAmount(stick.currentBalance || 0);
                                        setWithdrawStick(stick);
                                    }}
                                    disabled={!stick.currentBalance || stick.currentBalance <= 0}
                                    className="py-3 bg-white border border-slate-200 hover:bg-red-50 hover:text-red-600 hover:border-red-200 disabled:opacity-50 text-slate-600 rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 text-sm"
                                >
                                    <ArrowDownLeft size={16} /> {t('ind.withdraw')}
                                </button>
                            </div>

                            {/* Timeline & Transaction History (Only visible if expanded) */}
                            {isExpanded && (
                                <div className="border-t border-slate-100 pt-6 animate-fade-in grid md:grid-cols-2 gap-8">
                                    {/* Timeline Column */}
                                    <div>
                                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                                            <CalendarClock size={14} /> {t('ind.timeline')}
                                        </h4>
                                        <div className="relative pl-4 border-l-2 border-slate-200 ml-2 space-y-8">
                                            {/* Start Node */}
                                            <div className="relative">
                                                <div className="absolute -left-[21px] top-1 w-4 h-4 bg-emerald-500 rounded-full border-2 border-white ring-1 ring-slate-200"></div>
                                                <p className="text-xs font-bold text-slate-900">{t('ind.timeline_start')}</p>
                                                <p className="text-[10px] text-slate-500">{formatDate(stick.startDate)}</p>
                                            </div>

                                            {/* Today/Current Node */}
                                            <div className="relative">
                                                <div className="absolute -left-[21px] top-1 w-4 h-4 bg-purple-500 rounded-full border-2 border-white ring-1 ring-slate-200"></div>
                                                <p className="text-xs font-bold text-slate-900">{t('ind.timeline_today')}</p>
                                                <p className="text-[10px] text-slate-500">{formatCurrency(stick.currentBalance || 0)} Saved</p>
                                            </div>

                                            {/* Projected Node */}
                                            <div className="relative">
                                                <div className={`absolute -left-[21px] top-1 w-4 h-4 rounded-full border-2 border-white ring-1 ring-slate-200 ${projectedDate ? 'bg-slate-400' : 'bg-slate-200'}`}></div>
                                                <p className={`text-xs font-bold ${projectedDate ? 'text-slate-900' : 'text-slate-400'}`}>{t('ind.timeline_projected')}</p>
                                                <p className="text-[10px] text-slate-500">
                                                    {projectedDate ? formatDate(projectedDate.toISOString()) : t('ind.timeline_unknown')}
                                                </p>
                                            </div>
                                        </div>
                                    </div>

                                    {/* History Column */}
                                    <div>
                                        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">{t('ind.history')}</h4>
                                        <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar pr-1">
                                            {!stick.transactions || stick.transactions.length === 0 ? (
                                                <p className="text-xs text-slate-400 italic text-center py-2">{t('detail.empty_history')}</p>
                                            ) : (
                                                stick.transactions.map(tx => (
                                                    <div key={tx.id} className="flex justify-between items-center text-sm p-3 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors border border-slate-100">
                                                        <div className="flex items-center gap-3">
                                                            <div className={`w-2 h-2 rounded-full ${tx.type === TransactionType.DEPOSIT ? 'bg-green-500' : 'bg-red-500'}`}></div>
                                                            <div>
                                                                <div className="text-slate-700 font-bold text-xs">{tx.type === TransactionType.DEPOSIT ? t('ind.type_deposit') : t('ind.type_withdrawal')}</div>
                                                                <div className="text-[10px] text-slate-400">{new Date(tx.date).toLocaleDateString()}</div>
                                                            </div>
                                                        </div>
                                                        <div className={`font-bold font-mono ${tx.type === TransactionType.DEPOSIT ? 'text-green-600' : 'text-red-600'}`}>
                                                            {tx.type === TransactionType.DEPOSIT ? '+' : '-'}{formatCurrency(tx.amount)}
                                                        </div>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )}

                            {!isExpanded && stick.transactions && stick.transactions.length > 0 && (
                                <div className="text-center">
                                    <span className="text-[10px] text-slate-400 font-medium cursor-pointer hover:text-purple-500">View History ({stick.transactions.length})</span>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        )}
    </div>
  );
};

