        </div>
        <div className="flex items-center gap-3">
             <button onClick={() => setShowNotif(!showNotif)} className="relative p-1">
                <Bell size={20} className="text-slate-300" />
                {unreadCount > 0 && <span className="absolute -top-1 -right-1 bg-red-500 w-2 h-2 rounded-full"></span>}
             </button>
             <button onClick={toggleLanguage} className="p-1 text-slate-300 flex items-center gap-1 text-xs font-bold border border-slate-600 rounded px-2 py-1">
                <Globe size={14} /> {language.toUpperCase()}
            </button>
        </div>
      </div>

      {/* Sidebar / Bottom Nav */}
      <nav className="bg-slate-900 md:w-72 md:h-screen md:fixed md:left-0 md:top-0 border-r border-slate-800 flex flex-row md:flex-col justify-around md:justify-start fixed bottom-0 w-full md:relative z-40 shadow-inner md:shadow-none pb-safe">
        <div className="hidden md:block p-8 border-b border-slate-800">
          <div className="flex items-center gap-3 mb-2">
             <div className="bg-emerald-500/10 p-2 rounded-lg">
                <Gem className="text-emerald-400" size={28} />
             </div>
             <h1 className="text-2xl font-bold text-white tracking-tight">{t('app.name')}</h1>
          </div>
          <p className="text-xs text-slate-400 font-medium tracking-wide uppercase mt-2">{t('app.subtitle')}</p>
        </div>

        <div className="flex md:flex-col w-full md:p-4 justify-around md:justify-start md:space-y-2 md:mt-4">
          <NavButton 
            active={activeView === 'dashboard'} 
            onClick={() => onChangeView('dashboard')} 
            icon={<LayoutDashboard size={22} />} 
            label={t('nav.dashboard')} 
          />
          <NavButton 
            active={activeView === 'individual'} 
            onClick={() => onChangeView('individual')} 
            icon={<PiggyBank size={22} />} 
            label={t('nav.individual')} 
          />
          <NavButton 
            active={activeView === 'create'} 
            onClick={() => onChangeView('create')} 
            icon={<PlusCircle size={22} />} 
            label={t('nav.create')} 
          />
          <NavButton 
            active={activeView === 'simulation'} 
            onClick={() => onChangeView('simulation')} 
            icon={<Calculator size={22} />} 
            label={t('nav.simulation')} 
          />
          <NavButton 
            active={activeView === 'info'} 
            onClick={() => onChangeView('info')} 
            icon={<Info size={22} />} 
            label={t('nav.architecture')} 
          />
        </div>

        <div className="hidden md:block mt-auto p-6">
            <div className="flex items-center justify-between mb-4 px-1">
                 <div className="text-slate-400 text-xs font-bold uppercase tracking-wider">{t('nav.notifications')}</div>
                 <button onClick={() => setShowNotif(!showNotif)} className="relative hover:bg-slate-800 p-2 rounded-lg transition-colors">
