                {notifications.length === 0 ? (
                    <div className="p-8 text-center text-slate-400 text-sm">{t('nav.no_notifications')}</div>
                ) : (
                    notifications.map(n => (
                        <div key={n.id} className={`p-4 border-b border-slate-50 hover:bg-slate-50 transition-colors ${!n.read ? 'bg-blue-50/50' : ''}`}>
                             <div className="flex justify-between items-start mb-1">
                                 <h4 className={`text-sm font-bold ${n.type === 'warning' ? 'text-red-600' : 'text-slate-800'}`}>{n.title}</h4>
                                 {!n.read && <button onClick={() => handleMarkRead(n.id)} title={t('nav.mark_read')}><Check size={14} className="text-emerald-500" /></button>}
