import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Wizard from './components/Wizard';
import XitiqueDetail from './components/XitiqueDetail';
import Simulation from './components/Simulation';
import ArchitectureInfo from './components/ArchitectureInfo';
import UserProfile from './components/UserProfile';
import { Xitique } from './types';
import { deleteXitique } from './services/storage';

type View = 'dashboard' | 'create' | 'detail' | 'simulation' | 'info' | 'user';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [selectedXitique, setSelectedXitique] = useState<Xitique | null>(null);

  const handleSelectXitique = (xitique: Xitique) => {
    setSelectedXitique(xitique);
    setCurrentView('detail');
  };

  const handleDeleteXitique = () => {
    if (selectedXitique) {
        deleteXitique(selectedXitique.id);
        setSelectedXitique(null);
        setCurrentView('dashboard');
        // Force refresh by key change or relying on dashboard internal effect
        // In this simple structure, Dashboard remounts and fetches from storage.
        window.location.reload(); // Simple way to force refresh in this no-router demo
    }
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <Dashboard 
            onCreate={() => setCurrentView('create')}
            onSelect={handleSelectXitique}
          />
        );
      case 'create':
        return (
          <Wizard 
            onComplete={() => setCurrentView('dashboard')}
            onCancel={() => setCurrentView('dashboard')}
          />
        );
      case 'detail':
        return selectedXitique ? (
          <XitiqueDetail 
            xitique={selectedXitique} 
            onBack={() => {
              setSelectedXitique(null);
              setCurrentView('dashboard');
            }}
            onDelete={handleDeleteXitique}
          />
        ) : (
          <Dashboard onCreate={() => setCurrentView('create')} onSelect={handleSelectXitique} />
        );
      case 'simulation':
        return <Simulation />;
      case 'info':
        return <ArchitectureInfo />;
      case 'user':
        return <UserProfile />;
      default:
        return <Dashboard onCreate={() => setCurrentView('create')} onSelect={handleSelectXitique} />;
    }
  };

  return (
    <Layout activeView={currentView} onChangeView={(view) => setCurrentView(view as View)}>
      {renderContent()}
    </Layout>
  );
};

export default App;

