import { Transaction, TransactionType, Xitique } from '../types';

/**
 * CORE PRINCIPLE: All balances must be derived from transactions.
 * Never rely on a stored 'currentBalance' property.
 */
export const calculateBalance = (transactions: Transaction[]): number => {
  if (!transactions) return 0;

  return transactions.reduce((acc, tx) => {
    switch (tx.type) {
      case TransactionType.DEPOSIT:
        return acc + tx.amount;
      case TransactionType.WITHDRAWAL:
        return acc - tx.amount;
      // PAYOUT usually reduces the pool in a group setting, 
      // or resets the accumulator in a personal setting depending on logic.
      // For INDIVIDUAL xitique, a PAYOUT is essentially a withdrawal/liquidation.
      case TransactionType.PAYOUT: 
        return acc; // In Individual, Payouts are visual markers or separate logic, usually withdrawals handle the money movement.
      default:
        return acc;
    }
  }, 0);
};

/**
 * Validates if a transaction can occur based on business rules.
 */
export const validateTransaction = (
  xitique: Xitique, 
  type: TransactionType, 
  amount: number
): { valid: boolean; error?: string } => {

  if (amount <= 0) {
    return { valid: false, error: "Amount must be positive." };
  }

  const currentBalance = calculateBalance(xitique.transactions);

  if (type === TransactionType.WITHDRAWAL) {
    if (currentBalance < amount) {
      return { valid: false, error: "Insufficient funds." };
    }
  }

  return { valid: true };
};

/**
 * Creates a standard transaction object to ensure data integrity.
 */
export const createTransaction = (
  type: TransactionType,
  amount: number,
  description: string,
  referenceId?: string
): Transaction => {
  return {
    id: crypto.randomUUID(),
    date: new Date().toISOString(),
    type,
    amount,
    description,
    referenceId
  };
};

