import React from 'react';
import { AlertTriangle, CheckCircle2, X } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface ConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  description: string;
  type: 'danger' | 'success' | 'info';
  confirmText?: string;
  cancelText?: string;
}

const ConfirmationModal: React.FC<ConfirmationModalProps> = ({
  isOpen,
  onClose,
  onConfirm,
  title,
  description,
  type,
  confirmText,
  cancelText
}) => {
  const { t } = useLanguage();

  if (!isOpen) return null;

  const styles = {
    danger: {
      iconBg: 'bg-red-100',
      iconColor: 'text-red-600',
      btnBg: 'bg-red-600 hover:bg-red-700',
      icon: <AlertTriangle size={24} />
    },
    success: {
      iconBg: 'bg-emerald-100',
      iconColor: 'text-emerald-600',
      btnBg: 'bg-emerald-600 hover:bg-emerald-700',
      icon: <CheckCircle2 size={24} />
    },
    info: {
      iconBg: 'bg-blue-100',
      iconColor: 'text-blue-600',
      btnBg: 'bg-blue-600 hover:bg-blue-700',
      icon: <CheckCircle2 size={24} />
    }
  };

  const currentStyle = styles[type];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 animate-fade-in">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      ></div>

      {/* Modal */}
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 transform transition-all scale-100">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors"
        >
          <X size={20} />
        </button>

        <div className="flex items-start gap-4">
          <div className={`p-3 rounded-full flex-shrink-0 ${currentStyle.iconBg} ${currentStyle.iconColor}`}>
            {currentStyle.icon}
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-900 mb-2">
              {title}
            </h3>
            <p className="text-slate-500 text-sm leading-relaxed mb-6">
              {description}
            </p>

            <div className="flex gap-3">
              <button 
                onClick={onClose}
                className="flex-1 px-4 py-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 font-semibold rounded-xl transition-colors"
              >
                {cancelText || t('detail.cancel')}
              </button>
              <button 
                onClick={() => { onConfirm(); onClose(); }}
                className={`flex-1 px-4 py-2.5 text-white font-semibold rounded-xl shadow-lg transition-colors ${currentStyle.btnBg}`}
              >
                {confirmText || t('common.confirm')}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConfirmationModal;

import React, { useState, useEffect } from 'react';
import { Xitique, Participant, TransactionType } from '../types';
import { formatDate } from '../services/dateUtils';
import { formatCurrency } from '../services/formatUtils';
import { analyzeFairness } from '../services/geminiService';
import { saveXitique, deleteXitique } from '../services/storage';
import { createTransaction } from '../services/financeLogic';
import { Sparkles, Calendar, DollarSign, Users, ArrowLeft, Trash, CheckCircle2, Clock, Pencil, X, Check, History } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import FinancialTip from './FinancialTip';
import ConfirmationModal from './ConfirmationModal';

interface Props {
  xitique: Xitique;
  onBack: () => void;
  onDelete: () => void;
}

const XitiqueDetail: React.FC<Props> = ({ xitique, onBack, onDelete }) => {
  const { t } = useLanguage();
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [activeTab, setActiveTab] = useState<'schedule' | 'analysis' | 'history'>('schedule');

  // Edit State
  const [isEditing, setIsEditing] = useState(false);
  const [newAmount, setNewAmount] = useState(xitique.amount);

  // Modal State
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    type: 'danger' | 'success' | 'info';
    title: string;
    desc: string;
    action: () => void;
    confirmText?: string;
  }>({
    isOpen: false,
    type: 'info',
    title: '',
    desc: '',
    action: () => {}
  });

  useEffect(() => {
    setNewAmount(xitique.amount);
  }, [xitique.amount]);

  const potSize = xitique.amount * xitique.participants.length;

  const handleRunAnalysis = async () => {
    setLoadingAi(true);
    const result = await analyzeFairness(xitique);
    setAiAnalysis(result);
    setLoadingAi(false);
  };

  const handleToggleClick = (participantId: string) => {
    const participant = xitique.participants.find(p => p.id === participantId);
    if (!participant) return;

    if (!participant.received) {
        // Confirmation for Paying
        setConfirmModal({
            isOpen: true,
            type: 'success',
            title: `${t('modal.payout_title')}: ${participant.name}`,
            desc: `${t('modal.payout_desc')} (${formatCurrency(potSize)})`,
            confirmText: t('modal.confirm_payout'),
            action: () => executeToggle(participantId)
        });
    } else {
        // Confirmation for Reversing
        setConfirmModal({
            isOpen: true,
            type: 'danger',
            title: t('modal.reversal_title'),
            desc: t('modal.reversal_desc'),
            confirmText: t('modal.confirm_reversal'),
            action: () => executeToggle(participantId)
        });
    }
  };

  const executeToggle = (participantId: string) => {
    const participant = xitique.participants.find(p => p.id === participantId);
    if (!participant) return;

    // Toggle logic
    const willReceive = !participant.received;

    // CORE PRINCIPLE: Immutability
    // We do NOT modify or delete old transactions. We append new ones to the history.
    let newTx;
    if (willReceive) {
        newTx = createTransaction(
            TransactionType.PAYOUT,
            potSize,
            `${t('ind.type_payout')}: ${participant.name}`
        );
    } else {
        // CORRECTION: If unmarking, we create a REVERSAL transaction.
        newTx = createTransaction(
            TransactionType.PAYOUT_REVERSAL,
            potSize,
            `Correction (Reversal): ${participant.name}`
        );
    }

    // Append new transaction to the top of the history list
    const updatedTx = [newTx, ...(xitique.transactions || [])];

    // Update participant state
    const updatedParticipants = xitique.participants.map(p => 
      p.id === participantId ? { ...p, received: willReceive } : p
    );

    const updatedXitique = { 
        ...xitique, 
        participants: updatedParticipants,
        transactions: updatedTx
    };

    saveXitique(updatedXitique);

    // Update local references to force UI refresh logic if needed
    // (In a full app, we would use a reducer or context refresh here)
    xitique.participants = updatedParticipants; 
    xitique.transactions = updatedTx;
    setAiAnalysis(null); 
  };

  const saveContributionChange = () => {
    if (newAmount <= 0) return;
    const updatedXitique = { ...xitique, amount: newAmount };
    saveXitique(updatedXitique);
    xitique.amount = newAmount; // Update local ref
    setIsEditing(false);
  };

  const requestDelete = () => {
      setConfirmModal({
          isOpen: true,
          type: 'danger',
          title: t('modal.delete_title'),
          desc: t('modal.delete_desc'),
          confirmText: t('modal.confirm_delete'),
          action: onDelete
      });
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
      {/* Confirmation Modal */}
      <ConfirmationModal 
        isOpen={confirmModal.isOpen}
        onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
        onConfirm={confirmModal.action}
        title={confirmModal.title}
        description={confirmModal.desc}
        type={confirmModal.type}
        confirmText={confirmModal.confirmText}
      />

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 transition-colors font-medium">
          <ArrowLeft size={20} className="mr-2" /> {t('detail.back')}
        </button>
        <div className="flex gap-2">
            <button 
                onClick={requestDelete}
                className="text-red-500 hover:bg-red-50 px-4 py-2 rounded-xl flex items-center text-sm font-medium transition-colors"
            >
                <Trash size={18} className="mr-2" /> {t('detail.delete')}
            </button>
        </div>
      </div>

      <FinancialTip context="group" />

      <div className="bg-slate-900 text-white rounded-3xl p-8 shadow-xl relative overflow-hidden">
        <div className="absolute right-0 top-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

        <div className="relative z-10">
            <div className="flex items-center gap-3 mb-2">
                <span className="bg-emerald-500 text-slate-900 text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">{xitique.frequency === 'WEEKLY' ? t('wiz.weekly') : t('wiz.monthly')}</span>
            </div>
            <h1 className="text-4xl font-bold mb-6 tracking-tight">{xitique.name}</h1>

            <div className="flex flex-wrap gap-4">
                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10 relative group">
                    <div className="bg-emerald-400/20 p-2 rounded-lg">
                        <DollarSign size={20} className="text-emerald-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold flex items-center gap-2">
                            {t('detail.contribution_per_person')}
                            <button onClick={() => setIsEditing(true)} className="hover:text-white transition-colors"><Pencil size={12} /></button>
                        </div>
                        <div className="text-xl font-bold">{formatCurrency(xitique.amount)}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-emerald-400/20 p-2 rounded-lg">
                        <DollarSign size={20} className="text-emerald-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.total_payout')}</div>
                        <div className="text-xl font-bold">{formatCurrency(potSize)}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-blue-400/20 p-2 rounded-lg">
                        <Users size={20} className="text-blue-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.members')}</div>
                        <div className="text-xl font-bold">{xitique.participants.length}</div>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md px-4 py-3 rounded-xl border border-white/10">
                    <div className="bg-purple-400/20 p-2 rounded-lg">
                        <Calendar size={20} className="text-purple-400" />
                    </div>
                    <div>
                        <div className="text-xs text-slate-300 uppercase font-semibold">{t('detail.start_date')}</div>
                        <div className="text-xl font-bold">{formatDate(xitique.startDate)}</div>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {isEditing && (
          <div className="bg-white border-2 border-emerald-100 p-6 rounded-2xl shadow-lg flex flex-col md:flex-row items-center gap-4 animate-fade-in">
              <div className="flex-1">
                  <h3 className="font-bold text-slate-900 mb-1">{t('detail.edit_contribution')}</h3>
                  <p className="text-xs text-slate-500">This will update the total payout for all future turns.</p>
              </div>
              <div className="flex items-center gap-2">
                  <div className="relative">
                      <span className="absolute left-3 top-3 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                      <input 
                        type="number" 
                        value={newAmount} 
                        onChange={(e) => setNewAmount(Number(e.target.value))}
                        className="pl-10 p-2 border border-slate-300 rounded-lg w-32 font-bold text-slate-900 focus:ring-2 focus:ring-emerald-500 outline-none"
                      />
                  </div>
                  <button onClick={saveContributionChange} className="bg-emerald-500 hover:bg-emerald-600 text-white p-2.5 rounded-lg transition-colors">
                      <Check size={18} />
                  </button>
                  <button onClick={() => { setIsEditing(false); setNewAmount(xitique.amount); }} className="bg-slate-100 hover:bg-slate-200 text-slate-500 p-2.5 rounded-lg transition-colors">
                      <X size={18} />
                  </button>
              </div>
          </div>
      )}

      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button 
          onClick={() => setActiveTab('schedule')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'schedule' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          {t('detail.tab_schedule')}
          {activeTab === 'schedule' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-500 rounded-t-full" />}
        </button>
        <button 
          onClick={() => setActiveTab('history')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'history' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <span className="flex items-center gap-2">
            <History size={16} /> {t('detail.tab_history')}
          </span>
          {activeTab === 'history' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-500 rounded-t-full" />}
        </button>
        <button 
          onClick={() => setActiveTab('analysis')}
          className={`pb-4 px-6 font-semibold text-sm transition-colors relative ${activeTab === 'analysis' ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <span className="flex items-center gap-2">
            <Sparkles size={16} className="text-purple-500" /> {t('detail.tab_analysis')}
          </span>
          {activeTab === 'analysis' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-purple-500 rounded-t-full" />}
        </button>
      </div>

      {activeTab === 'schedule' && (
        <div className="space-y-4">
          <div className="grid gap-4">
            {xitique.participants.map((p, idx) => (
              <div 
                key={p.id} 
                className={`flex flex-col md:flex-row md:items-center justify-between p-5 rounded-2xl border transition-all ${
                  p.received 
                    ? 'bg-emerald-50/50 border-emerald-100' 
                    : 'bg-white border-slate-200 hover:border-emerald-200 shadow-sm'
                }`}
              >
                <div className="flex items-center gap-5 mb-4 md:mb-0">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-xl shadow-sm ${
                    p.received ? 'bg-emerald-200 text-emerald-800' : 'bg-slate-100 text-slate-600'
                  }`}>
                    {idx + 1}
                  </div>
                  <div>
                    <h3 className={`font-bold text-lg ${p.received ? 'text-emerald-900' : 'text-slate-900'}`}>
                      {p.name}
                    </h3>
                    <div className="flex items-center gap-2 text-sm text-slate-500 mt-1">
                        <Clock size={14} />
                        {p.payoutDate ? formatDate(p.payoutDate) : t('detail.date_tbd')}
                    </div>
                  </div>
                </div>

                <div className="flex items-center justify-end">
                   <button 
                      onClick={() => handleToggleClick(p.id)}
                      className={`flex items-center gap-3 px-5 py-2.5 rounded-xl font-medium transition-all ${
                          p.received 
                          ? 'bg-emerald-500 text-white shadow-emerald-200 shadow-lg' 
                          : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                      }`}
                   >
                      {p.received ? (
                          <>
                            <CheckCircle2 size={18} /> {t('detail.paid_out')}
                          </>
                      ) : (
                          <>
                            <div className="w-4 h-4 rounded-full border-2 border-slate-400"></div> {t('detail.mark_paid')}
                          </>
                      )}
                   </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
            {!xitique.transactions || xitique.transactions.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                    <History size={48} className="mx-auto mb-4 opacity-20" />
                    <p>{t('detail.empty_history')}</p>
                </div>
            ) : (
                <div className="divide-y divide-slate-100">
                    {xitique.transactions.map((tx) => (
                        <div key={tx.id} className="p-4 flex justify-between items-center hover:bg-slate-50">
                            <div>
                                <div className="font-bold text-slate-800 text-sm">{tx.description}</div>
                                <div className="text-xs text-slate-500">{new Date(tx.date).toLocaleDateString()} {new Date(tx.date).toLocaleTimeString()}</div>
                            </div>
                            <div className="text-right">
                                <div className={`font-bold ${tx.type === TransactionType.PAYOUT_REVERSAL ? 'text-red-500 line-through' : 'text-emerald-600'}`}>
                                    {formatCurrency(tx.amount)}
                                </div>
                                <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">{tx.type.replace('_', ' ')}</div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm min-h-[400px]">
          {!aiAnalysis ? (
            <div className="text-center py-16">
              <div className="w-20 h-20 bg-purple-50 text-purple-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <Sparkles size={40} />
              </div>
              <h3 className="text-2xl font-bold text-slate-900 mb-3">{t('detail.ai_title')}</h3>
              <p className="text-slate-500 max-w-md mx-auto mb-8">
                {t('detail.ai_desc')}
              </p>
              <button 
                onClick={handleRunAnalysis}
                disabled={loadingAi}
                className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-4 rounded-xl font-bold shadow-xl shadow-slate-200 transition-all disabled:opacity-50 flex items-center gap-2 mx-auto"
              >
                {loadingAi ? (
                    <>{t('detail.ai_running')}</>
                ) : (
                    <>
                        <Sparkles size={18} /> {t('detail.ai_btn')}
                    </>
                )}
              </button>
            </div>
          ) : (
             <div className="prose prose-slate max-w-none">
                <div className="flex items-center gap-4 mb-8 pb-6 border-b border-slate-100">
                   <div className="bg-purple-100 p-3 rounded-xl text-purple-700">
                      <Sparkles size={28} />
                   </div>
                   <div>
                       <h3 className="text-xl font-bold text-slate-900 m-0">{t('detail.ai_report')}</h3>
                       <p className="text-slate-500 text-sm">{t('detail.ai_generated')}</p>
                   </div>
                </div>
                <div className="whitespace-pre-wrap text-slate-700 leading-relaxed bg-slate-50 p-8 rounded-2xl border border-slate-200 font-medium">
                  {aiAnalysis}
                </div>
                <button 
                  onClick={() => setAiAnalysis(null)}
                  className="mt-8 text-slate-500 font-semibold hover:text-slate-900 text-sm flex items-center gap-2"
                >
                  <ArrowLeft size={16} /> {t('detail.ai_reset')}
                </button>
             </div>
          )}
        </div>
      )}
    </div>
  );
};

export default XitiqueDetail;

import { Xitique, Notification, XitiqueType, XitiqueStatus } from '../types';
import { getXitiques } from './storage';
import { formatCurrency } from './formatUtils';

const NOTIF_STORAGE_KEY = 'xitique_notifications_v1';

export const getNotifications = (): Notification[] => {
  const data = localStorage.getItem(NOTIF_STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const saveNotifications = (notifications: Notification[]): void => {
  localStorage.setItem(NOTIF_STORAGE_KEY, JSON.stringify(notifications));
};

export const markNotificationRead = (id: string): Notification[] => {
  const current = getNotifications();
  const updated = current.map(n => n.id === id ? { ...n, read: true } : n);
  saveNotifications(updated);
  return updated;
};

/**
 * Pure function to generate notifications based on state.
 * Designed to be portable to Cloud Functions in the future.
 * @param xitiques List of all xitiques
 * @param existingIds Set of notification IDs already generated to prevent duplicates
 * @param referenceDate The "current" date (defaults to now)
 */
export const generateNotificationsLogic = (
  xitiques: Xitique[], 
  existingIds: Set<string>,
  referenceDate: Date = new Date()
): Notification[] => {
  const newNotifications: Notification[] = [];

  xitiques.forEach(x => {
    if (x.status === XitiqueStatus.ACTIVE || x.status === XitiqueStatus.PLANNING) {

      // GROUP LOGIC
      if (x.type === XitiqueType.GROUP) {
        x.participants.forEach(p => {
          if (!p.received && p.payoutDate) {
            const pDate = new Date(p.payoutDate);
            // Reset time to start of day for accurate day diff comparison
            const pDateStart = new Date(pDate.setHours(0,0,0,0));
            const refDateStart = new Date(referenceDate.setHours(0,0,0,0));

            const diffTime = pDateStart.getTime() - refDateStart.getTime();
            const diffDays = Math.round(diffTime / (1000 * 60 * 60 * 24));

            const payoutAmount = formatCurrency(x.amount * x.participants.length);

            // 1. Contribution Reminder (2 days before)
            // ACTIONABLE: Remind admin to collect money specifically for the upcoming person.
            if (diffDays <= 2 && diffDays > 0) {
              const notifId = `contrib-${x.id}-${p.id}-${diffDays}`;
              if (!existingIds.has(notifId)) {
                 newNotifications.push({
                  id: notifId,
                  title: `Upcoming Rotation: ${p.name}`,
                  message: `Preparation time! The group needs to collect contributions for ${p.name} in ${diffDays} days.`,
                  date: referenceDate.toISOString(),
                  read: false,
                  type: 'info'
                });
                existingIds.add(notifId);
              }
            }

            // 2. Payout Due (Day 0)
            // ACTIONABLE: Explicit instruction to pay.
            if (diffDays === 0) {
              const notifId = `payout-${x.id}-${p.id}`;
              if (!existingIds.has(notifId)) {
                newNotifications.push({
                  id: notifId,
                  title: `Payout Day: ${p.name}`,
                  message: `Today is the day! Please ensure ${p.name} receives ${payoutAmount}. Mark as paid when done.`,
                  date: referenceDate.toISOString(),
                  read: false,
                  type: 'success'
                });
                existingIds.add(notifId);
              }
            }

            // 3. Overdue (Negative)
            // ACTIONABLE: Warning.
            if (diffDays < 0 && diffDays > -30) { // Don't spam forever
               const notifId = `overdue-${x.id}-${p.id}-${diffDays}`; 
               // Note: including diffDays in ID ensures we remind every day it's late if we wanted, 
               // but simpler logic here checks if generic overdue ID exists. 
               // Let's stick to one overdue notification per person to avoid spam.
               const baseOverdueId = `overdue-${x.id}-${p.id}`;

               if (!existingIds.has(baseOverdueId)) {
                newNotifications.push({
                  id: baseOverdueId,
                  title: `Attention: Overdue Payout`,
                  message: `${p.name} was scheduled to receive ${payoutAmount} on ${pDate.toLocaleDateString()}. Has this been settled?`,
                  date: referenceDate.toISOString(),
                  read: false,
                  type: 'warning'
                });
                existingIds.add(baseOverdueId);
               }
            }
          }
        });
      }

      // PERSONAL LOGIC (Simplified)
      if (x.type === XitiqueType.INDIVIDUAL) {
         const created = new Date(x.createdAt || Date.now());
         const diffCreated = Math.ceil((referenceDate.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));

         // Weekly encouragement
         if (diffCreated > 0 && diffCreated % 7 === 0 && (calculateDerivedBalance(x) || 0) < (x.targetAmount || 1)) {
             const notifId = `ind-reminder-${x.id}-${diffCreated}`;
             if (!existingIds.has(notifId)) {
                 newNotifications.push({
                     id: notifId,
                     title: 'Savings Goal Reminder',
                     message: `It's been another week on your '${x.name}' goal. Keep going! Every Metical counts.`,
                     date: referenceDate.toISOString(),
                     read: false,
                     type: 'success'
                 });
                 existingIds.add(notifId);
             }
         }
      }
    }
  });

  return newNotifications;
};

// Helper to avoid circular dependency with financeLogic if needed, 
// though importing financeLogic is better practice if strictly layered.
// For now, using a simplified sum logic for notifications to keep it lightweight.
const calculateDerivedBalance = (x: Xitique) => {
    return x.transactions?.reduce((acc, t) => {
        if(t.type === 'DEPOSIT') return acc + t.amount;
        if(t.type === 'WITHDRAWAL') return acc - t.amount;
        return acc;
    }, 0) || 0;
};

export const checkAndGenerateNotifications = (): Notification[] => {
  const xitiques = getXitiques();
  const existingNotifications = getNotifications();

  const existingIds = new Set(existingNotifications.map(n => n.id));

  const generated = generateNotificationsLogic(xitiques, existingIds);

  if (generated.length > 0) {
      // Prepend new notifications
      const updated = [...generated, ...existingNotifications];
      saveNotifications(updated);
      return updated;
  }

  return existingNotifications;
};

import React, { useState, useEffect } from 'react';
import { Xitique, XitiqueType, Frequency, PaymentMethod, TransactionType } from '../types';
import { getXitiques, saveXitique, createNewXitique, deleteXitique } from '../services/storage';
import { calculateBalance, createTransaction, validateTransaction } from '../services/financeLogic';
import { formatCurrency } from '../services/formatUtils';
import { PiggyBank, Plus, Smartphone, Banknote, Trash, X, ShieldAlert } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import FinancialTip from './FinancialTip';
import ConfirmationModal from './ConfirmationModal';

const IndividualDashboard: React.FC = () => {
  const { t } = useLanguage();
  const [sticks, setSticks] = useState<Xitique[]>([]);
  const [isCreating, setIsCreating] = useState(false);

  // Withdrawal State
  const [withdrawStick, setWithdrawStick] = useState<Xitique | null>(null);
  const [withdrawAmount, setWithdrawAmount] = useState<number>(0);
  const [withdrawError, setWithdrawError] = useState<string>('');

  // Confirmation Modal State
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    type: 'danger' | 'success' | 'info';
    title: string;
    desc: string;
    action: () => void;
    confirmText?: string;
  }>({
    isOpen: false,
    type: 'info',
    title: '',
    desc: '',
    action: () => {}
  });

  // Form State
  const [name, setName] = useState('');
  const [targetAmount, setTargetAmount] = useState(5000);
  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.DAILY);
  const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.MPESA);

  const [expandedId, setExpandedId] = useState<string | null>(null);

  useEffect(() => {
    loadSticks();
  }, []);

  const loadSticks = () => {
    const all = getXitiques();
    setSticks(all.filter(x => x.type === XitiqueType.INDIVIDUAL));
  };

  const handleCreate = () => {
    if (!name) return alert(t('wiz.alert_name'));

    const newStick = createNewXitique({
      name,
      type: XitiqueType.INDIVIDUAL,
      targetAmount,
      amount,
      frequency,
      method,
      startDate: new Date().toISOString(),
      participants: []
    });

    saveXitique(newStick);
    setIsCreating(false);
    loadSticks();
    setName('');
    setTargetAmount(5000);
    setAmount(100);
  };

  const requestDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setConfirmModal({
        isOpen: true,
        type: 'danger',
        title: t('modal.delete_title'),
        desc: t('modal.delete_desc'),
        confirmText: t('modal.confirm_delete'),
        action: () => {
            deleteXitique(id); // Now performs soft delete
            loadSticks();
        }
    });
  };

  const handleDeposit = (stick: Xitique, e?: React.MouseEvent) => {
    if(e) e.stopPropagation();

    // Validate transaction via logic layer
    const validation = validateTransaction(stick, TransactionType.DEPOSIT, stick.amount);
    if (!validation.valid) {
        alert(validation.error);
        return;
    }

    const newTx = createTransaction(
        TransactionType.DEPOSIT,
        stick.amount,
        t('ind.type_deposit')
    );

    // CORE PRINCIPLE: Immutable Transactions
    // We strictly append to history. We do NOT edit `currentBalance` directly.
    const updated = {
      ...stick,
      transactions: [newTx, ...(stick.transactions || [])]
    };

    // Only updating currentBalance for legacy/UI cache if needed, but reliance is on calculation
    updated.currentBalance = calculateBalance(updated.transactions);

    saveXitique(updated);
    loadSticks();
  };

  const handleWithdraw = () => {
    if(!withdrawStick) return;

    const validation = validateTransaction(withdrawStick, TransactionType.WITHDRAWAL, withdrawAmount);
    if (!validation.valid) {
        setWithdrawError(validation.error || "Error");
        return;
    }

    const newTx = createTransaction(
        TransactionType.WITHDRAWAL,
        withdrawAmount,
        t('ind.type_withdrawal')
    );

    const updated = {
        ...withdrawStick,
        transactions: [newTx, ...(withdrawStick.transactions || [])]
    };
    // Cache update
    updated.currentBalance = calculateBalance(updated.transactions);

    saveXitique(updated);
    setWithdrawStick(null);
    setWithdrawAmount(0);
    setWithdrawError('');
    loadSticks();
  };

  const getMethodIcon = (m?: PaymentMethod) => {
    switch (m) {
      case PaymentMethod.MPESA: return <span className="bg-red-100 text-red-700 border border-red-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> M-Pesa</span>;
      case PaymentMethod.EMOLA: return <span className="bg-orange-100 text-orange-700 border border-orange-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> e-Mola</span>;
      default: return <span className="bg-emerald-100 text-emerald-700 border border-emerald-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Banknote size={12}/> Cash</span>;
    }
  };

  const getFrequencyLabel = (f: Frequency) => {
