            </div>

            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_freq')}</label>
                <div className="grid grid-cols-3 gap-2">
                    {[Frequency.DAILY, Frequency.WEEKLY, Frequency.MONTHLY].map(f => (
                        <button
                            key={f}
