const SESSION_KEY = 'xitique_auth_session_v1';

// Simulate API Delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const getSession = (): AuthSession | null => {
  const stored = localStorage.getItem(SESSION_KEY);
  return stored ? JSON.parse(stored) : null;
};

export const login = async (email: string, password: string): Promise<AuthSession> => {
  await delay(1200); // Fake network delay

  // In a real app, this sends data to backend
  // Here we just simulate a successful login if fields are filled
  if (!email || !password) throw new Error("Credentials required");

  // Retrieve existing profile or create a mock one based on login
  let profile = getUserProfile();

  // If guest, update with email
  if (profile.id === 'guest') {
    profile = {
      ...profile,
      id: crypto.randomUUID(),
      email: email,
      name: email.split('@')[0], // Derive name from email
      lastLogin: new Date().toISOString()
    };
    saveUserProfile(profile);
  } else {
    // Update login time
    profile.lastLogin = new Date().toISOString();
    saveUserProfile(profile);
  }

  const session: AuthSession = {
    user: profile,
    token: 'mock-jwt-token-' + Date.now()
  };

  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return session;
};

export const register = async (name: string, email: string, password: string): Promise<AuthSession> => {
  await delay(1500); // Fake network delay

  if (!email || !password || !name) throw new Error("All fields required");

  const newProfile: UserProfile = {
    id: crypto.randomUUID(),
    name: name,
    email: email,
    language: 'pt', // Default
    avatarColor: 'bg-emerald-500',
    joinedAt: Date.now(),
    lastLogin: new Date().toISOString(),
    notificationPreferences: {
      contributions: true,
      payouts: true,
      updates: true
    }
  };

  saveUserProfile(newProfile);

  const session: AuthSession = {
    user: newProfile,
    token: 'mock-jwt-token-' + Date.now()
  };

  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return session;
};

export const logout = async (): Promise<void> => {
  await delay(500);
  localStorage.removeItem(SESSION_KEY);
  // Optionally clear user profile if you want strict security, 
  // but for this offline-first demo, we might keep data.
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AuthSession, UserProfile } from '../types';
import { getSession, login as apiLogin, register as apiRegister, logout as apiLogout } from '../services/authService';

interface AuthContextType {
  user: UserProfile | null;
  loading: boolean;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => Promise<void>;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    initAuth();
  }, []);

  const initAuth = () => {
    const session = getSession();
    if (session) {
      setUser(session.user);
    }
    setLoading(false);
  };

  const login = async (email: string, pass: string) => {
    const session = await apiLogin(email, pass);
    setUser(session.user);
  };

  const register = async (name: string, email: string, pass: string) => {
    const session = await apiRegister(name, email, pass);
    setUser(session.user);
  };

  const logout = async () => {
    await apiLogout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      login, 
      register, 
      logout,
      isAuthenticated: !!user 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

