    // Ensure these exist if local profile was empty/guest
    notificationPreferences: localProfile.notificationPreferences || {
      contributions: true,
      payouts: true,
      updates: true
    }
  };
};

export const login = async (email: string, password: string): Promise<AuthSession> => {
  const userCredential = await signInWithEmailAndPassword(auth, email, password);
  const profile = mapFirebaseUserToProfile(userCredential.user);

  // Persist the mapped profile locally for the app to access synchronously
  saveUserProfile(profile);

  return {
    user: profile,
    token: await userCredential.user.getIdToken()
  };
};

export const register = async (name: string, email: string, password: string): Promise<AuthSession> => {
  const userCredential = await createUserWithEmailAndPassword(auth, email, password);

  // Update the display name in Firebase
  await updateProfile(userCredential.user, {
    displayName: name
  });

  const profile = mapFirebaseUserToProfile(userCredential.user);

  // Override name explicitly since updateProfile might not propagate to user object instantly in memory
  profile.name = name;

  saveUserProfile(profile);

  return {
    user: profile,
    token: await userCredential.user.getIdToken()
  };
};

