import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { auth } from '../services/firebase';
import { UserProfile } from '../types';
import { login as apiLogin, register as apiRegister, logout as apiLogout, mapFirebaseUserToProfile } from '../services/authService';
import { saveUserProfile } from '../services/storage';

interface AuthContextType {
  user: UserProfile | null;
  loading: boolean;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => Promise<void>;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Subscribe to Firebase Auth State
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        const profile = mapFirebaseUserToProfile(firebaseUser);
        setUser(profile);
        saveUserProfile(profile); // Sync with local storage for sync access
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const login = async (email: string, pass: string) => {
    await apiLogin(email, pass);
    // State update handled by onAuthStateChanged
  };

  const register = async (name: string, email: string, pass: string) => {
    await apiRegister(name, email, pass);
    // State update handled by onAuthStateChanged
  };

  const logout = async () => {
    await apiLogout();
    // State update handled by onAuthStateChanged
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      login, 
      register, 
      logout,
      isAuthenticated: !!user 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // User Profiles: Users can only read/write their own data
    match /users/{userId} {
      allow read, write: if request.auth != null && request.auth.uid == userId;
    }

    // User Preferences: Users can only read/write their own preferences
    match /preferences/{userId} {
      allow read, write: if request.auth != null && request.auth.uid == userId;
    }

    // Activity Logs: Users can read their own logs, and write logs if the user_id matches their UID
    match /activity_logs/{logId} {
      allow read: if request.auth != null && resource.data.user_id == request.auth.uid;
      allow create: if request.auth != null && request.resource.data.user_id == request.auth.uid;
    }
  }
}

