import { 
  doc, 
  getDoc, 
  setDoc, 
  updateDoc, 
  collection, 
  addDoc 
} from 'firebase/firestore';
import { db } from './firebase';
import { UserData, UserPreferences, UserProfile, ActivityLog } from '../types';

const USERS_COLLECTION = 'users';
const PREFS_COLLECTION = 'preferences';
const LOGS_COLLECTION = 'activity_logs';

/**
 * Logs a user action to Firestore for audit purposes.
 */
export const logActivity = async (
  userId: string, 
  action: ActivityLog['action'], 
  status: 'SUCCESS' | 'FAILURE' = 'SUCCESS',
  details?: string
): Promise<void> => {
  try {
    await addDoc(collection(db, LOGS_COLLECTION), {
      userId,
      action,
      status,
      details: details || '',
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    console.error("Failed to write activity log", error);
    // Do not throw, logging failure shouldn't break app flow
  }
};

/**
 * Fetches User Data and Preferences and combines them into UserProfile.
 */
export const fetchFullUserProfile = async (userId: string): Promise<UserProfile | null> => {
  try {
    const userSnap = await getDoc(doc(db, USERS_COLLECTION, userId));
    const prefsSnap = await getDoc(doc(db, PREFS_COLLECTION, userId));

    if (userSnap.exists()) {
      const userData = userSnap.data() as UserData;
      const prefsData = prefsSnap.exists() ? (prefsSnap.data() as UserPreferences) : null;

      return {
        ...userData,
        notificationPreferences: {
          contributions: prefsData?.contributions ?? true,
          payouts: prefsData?.payouts ?? true,
          updates: prefsData?.updates ?? false
        }
      };
    }
    return null;
  } catch (error) {
    console.error("Error fetching profile", error);
    return null;
  }
};

/**
 * Creates or Overwrites initial user data structure.
 */
export const initializeUserDocuments = async (user: UserData): Promise<void> => {
  const batch = [];

  // 1. Create User Document
  await setDoc(doc(db, USERS_COLLECTION, user.id), user);

  // 2. Create Default Preferences
  const defaultPrefs: UserPreferences = {
    userId: user.id,
    contributions: true,
    payouts: true,
    updates: false
  };
  await setDoc(doc(db, PREFS_COLLECTION, user.id), defaultPrefs);

  // 3. Log
  await logActivity(user.id, 'REGISTER', 'SUCCESS', 'Account created');
};

/**
 * Updates basic user profile info.
 */
export const updateUserProfileData = async (userId: string, data: Partial<UserData>): Promise<void> => {
  try {
    const userRef = doc(db, USERS_COLLECTION, userId);
    await updateDoc(userRef, data);
    await logActivity(userId, 'UPDATE_PROFILE', 'SUCCESS');
  } catch (e: any) {
    await logActivity(userId, 'UPDATE_PROFILE', 'FAILURE', e.message);
    throw e;
  }
};

/**
 * Updates notification preferences.
 */
export const updateUserPreferences = async (userId: string, prefs: Partial<UserPreferences>): Promise<void> => {
  try {
    const prefsRef = doc(db, PREFS_COLLECTION, userId);
    // Use setDoc with merge: true in case document doesn't exist yet for some reason
    await setDoc(prefsRef, prefs, { merge: true });
    await logActivity(userId, 'UPDATE_PREFS', 'SUCCESS');
  } catch (e: any) {
    await logActivity(userId, 'UPDATE_PREFS', 'FAILURE', e.message);
    throw e;
  }
};

import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut, 
  updateProfile,
  User 
} from 'firebase/auth';
import { auth } from './firebase';
import { UserProfile, AuthSession } from '../types';
import { 
  initializeUserDocuments, 
  fetchFullUserProfile, 
  logActivity,
  updateUserProfileData
} from './userService';

// Helper to Map Firebase User to Initial Data Structure
const mapAuthToUserData = (firebaseUser: User): UserProfile => {
  return {
    id: firebaseUser.uid,
    name: firebaseUser.displayName || firebaseUser.email?.split('@')[0] || 'User',
    email: firebaseUser.email || '',
    language: 'pt',
    lastLogin: new Date().toISOString(),
    photoUrl: firebaseUser.photoURL || undefined,
    notificationPreferences: {
      contributions: true,
      payouts: true,
      updates: false
    }
  };
};

export const login = async (email: string, password: string): Promise<AuthSession> => {
  try {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    const uid = userCredential.user.uid;

    // Fetch rich data from Firestore
    let profile = await fetchFullUserProfile(uid);

    // If profile doesn't exist in Firestore (e.g. legacy user), create it
    if (!profile) {
       profile = mapAuthToUserData(userCredential.user);
       await initializeUserDocuments(profile);
    } else {
       // Update last login
       await updateUserProfileData(uid, { lastLogin: new Date().toISOString() });
    }

    await logActivity(uid, 'LOGIN', 'SUCCESS');

    return {
      user: profile,
      token: await userCredential.user.getIdToken()
    };
  } catch (e: any) {
    // Attempt to log failure if we can identify user, otherwise generic log (omitted for simplicity)
    throw e;
  }
};

export const register = async (name: string, email: string, password: string): Promise<AuthSession> => {
  const userCredential = await createUserWithEmailAndPassword(auth, email, password);

  // Update Auth Profile
  await updateProfile(userCredential.user, {
    displayName: name
  });

  const profile = mapAuthToUserData(userCredential.user);
  profile.name = name; // Ensure name is set immediately

  // Create Firestore Documents
  await initializeUserDocuments(profile);

  return {
    user: profile,
    token: await userCredential.user.getIdToken()
  };
};

export const logout = async (): Promise<void> => {
  if (auth.currentUser) {
    await logActivity(auth.currentUser.uid, 'LOGIN', 'SUCCESS', 'Logged out');
  }
  await signOut(auth);
};

