const UserProfile: React.FC = () => {
  const { t, language, setLanguage } = useLanguage();
  const { addToast } = useToast();
  const { user, logout } = useAuth();

  // Local state for form editing
  const [profile, setProfile] = useState<UserProfileType | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // Security modals
  const [passwordModalOpen, setPasswordModalOpen] = useState(false);
  const [logoutModalOpen, setLogoutModalOpen] = useState(false);

  // Password Change State
  const [currentPass, setCurrentPass] = useState('');
  const [newPass, setNewPass] = useState('');

  useEffect(() => {
    if (user) {
      setProfile(user);
      if (user.language && user.language !== language) {
          setLanguage(user.language);
      }
    }
  }, [user]);

  const handleSaveProfile = async () => {
    if (!profile) return;
    setIsSaving(true);
    try {
      await updateUserProfileData(profile.id, {
        name: profile.name,
        email: profile.email,
        language: profile.language,
        photoUrl: profile.photoUrl
      });

      // Update Language Context
      setLanguage(profile.language);

      addToast(t('profile.saved'), 'success');
    } catch (error) {
      console.error(error);
      addToast('Failed to update profile', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleSavePreferences = async () => {
    if (!profile) return;
    setIsSaving(true);
    try {
      await updateUserPreferences(profile.id, {
        contributions: profile.notificationPreferences.contributions,
        payouts: profile.notificationPreferences.payouts,
        updates: profile.notificationPreferences.updates
      });
      addToast('Preferences updated', 'success');
    } catch (error) {
      addToast('Failed to update preferences', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleChangePassword = async () => {
    if (!auth.currentUser || !currentPass || !newPass) {
        addToast("Please fill in all fields", "error");
        return;
    }

    setIsSaving(true);
    try {
        // Re-authenticate first (Firebase Security Requirement)
        const credential = EmailAuthProvider.credential(auth.currentUser.email!, currentPass);
        await reauthenticateWithCredential(auth.currentUser, credential);

        // Update
        await updatePassword(auth.currentUser, newPass);

        addToast(t('profile.pass_updated'), 'success');
        setPasswordModalOpen(false);
        setCurrentPass('');
        setNewPass('');
    } catch (error: any) {
        console.error(error);
