const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();

// Scheduled job: Runs every day at 8:00 AM
exports.checkDailyReminders = functions.pubsub.schedule('every day 08:00')
  .timeZone('Africa/Maputo')
  .onRun(async (context) => {

    // 1. Get all active Xitiques from Firestore
    // Note: This assumes Xitiques are stored in 'xitiques' collection.
    const xitiquesSnapshot = await admin.firestore().collection('xitiques')
        .where('status', 'in', ['ACTIVE', 'RISK'])
        .get();

    const notifications = [];

    xitiquesSnapshot.forEach(doc => {
        const xitique = doc.data();
        const ownerId = xitique.ownerId; // Need this to find token

        if (!ownerId) return;

        // Logic for group payouts
        if (xitique.type === 'GROUP') {
            xitique.participants.forEach(p => {
                if (!p.received && p.payoutDate) {
                    const diffDays = getDaysDiff(new Date(), new Date(p.payoutDate));

                    if (diffDays === 2) {
                        notifications.push({
                            userId: ownerId,
                            title: `Upcoming Rotation: ${p.name}`,
                            body: `Time to collect! ${p.name} receives in 2 days.`
                        });
                    } else if (diffDays === 0) {
                         notifications.push({
                            userId: ownerId,
                            title: `Payout Day: ${p.name}`,
                            body: `Today is the day! Ensure ${p.name} receives their payout.`
                        });
                    }
                }
            });
        }
    });

    // 2. Send Notifications
    const promises = notifications.map(async (notif) => {
        // Fetch User Preference & Token
        const userDoc = await admin.firestore().collection('users').doc(notif.userId).get();
        const userPrefs = await admin.firestore().collection('preferences').doc(notif.userId).get();

        if (!userDoc.exists || !userPrefs.exists) return;

        const userData = userDoc.data();
        const prefs = userPrefs.data();

        // Check preference
        if (prefs.contributions && userData.fcmToken) {
            const message = {
                notification: {
                    title: notif.title,
                    body: notif.body
                },
                token: userData.fcmToken
            };

            try {
                await admin.messaging().send(message);
