import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { onAuthStateChanged } from 'firebase/auth';
import { auth } from '../services/firebase';
import { UserProfile } from '../types';
import { login as apiLogin, register as apiRegister, logout as apiLogout } from '../services/authService';

interface AuthContextType {
  user: UserProfile | null;
  loading: boolean;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => Promise<void>;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Subscribe to Firebase Auth State
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      // Only set the user if they exist AND are verified
      if (firebaseUser && firebaseUser.emailVerified) {
        // Map Auth user to local UserProfile structure without Firestore lookup
        const profile: UserProfile = {
            id: firebaseUser.uid,
            name: firebaseUser.displayName || firebaseUser.email?.split('@')[0] || 'User',
            email: firebaseUser.email || '',
            language: 'pt',
            lastLogin: new Date().toISOString(),
            photoUrl: firebaseUser.photoURL || undefined,
            notificationPreferences: { contributions: true, payouts: true, updates: false }
        };
        setUser(profile);
      } else {
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const login = async (email: string, pass: string) => {
    await apiLogin(email, pass);
    // State update handled by onAuthStateChanged listener
  };

  const register = async (name: string, email: string, pass: string) => {
    await apiRegister(name, email, pass);
    // Note: register now returns void and signs user out, so onAuthStateChanged will set user to null
  };

  const logout = async () => {
    await apiLogout();
    // State update handled by onAuthStateChanged listener
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      login, 
      register, 
      logout,
      isAuthenticated: !!user 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

