import { UserData, UserPreferences, UserProfile, ActivityLog } from '../types';

// Simulation of a backend database using LocalStorage
const USERS_DB_KEY = 'xitique_backend_users_v1';
const PREFS_DB_KEY = 'xitique_backend_prefs_v1';

const getDb = (key: string) => {
  try {
    const data = localStorage.getItem(key);
    return data ? JSON.parse(data) : {};
  } catch (e) {
    return {};
  }
};

const saveDb = (key: string, data: any) => {
  localStorage.setItem(key, JSON.stringify(data));
};

/**
 * Logs a user action (Console only for now to avoid storage bloat)
 */
export const logActivity = async (
  userId: string, 
  action: ActivityLog['action'], 
  status: 'SUCCESS' | 'FAILURE' = 'SUCCESS',
  details?: string
): Promise<void> => {
  console.log(`[Activity Log] User: ${userId} | Action: ${action} | Status: ${status} | ${details || ''}`);
};

/**
 * Fetches User Data and Preferences from LocalStorage
 */
export const fetchFullUserProfile = async (userId: string): Promise<UserProfile | null> => {
  const users = getDb(USERS_DB_KEY);
  const prefs = getDb(PREFS_DB_KEY);

  const userData = users[userId];
  if (userData) {
      const userPrefs = prefs[userId] || { contributions: true, payouts: true, updates: false };
      return {
          ...userData,
          notificationPreferences: {
              contributions: userPrefs.contributions ?? true,
              payouts: userPrefs.payouts ?? true,
              updates: userPrefs.updates ?? false
          }
      };
  }
  return null;
};

/**
 * Creates initial user data structure in LocalStorage
 */
export const initializeUserDocuments = async (user: UserData): Promise<void> => {
  const users = getDb(USERS_DB_KEY);
  const prefs = getDb(PREFS_DB_KEY);

  users[user.id] = user;
  prefs[user.id] = {
    userId: user.id,
    contributions: true,
    payouts: true,
    updates: false
  };

  saveDb(USERS_DB_KEY, users);
  saveDb(PREFS_DB_KEY, prefs);

  await logActivity(user.id, 'REGISTER', 'SUCCESS', 'Account created locally');
};

/**
 * Updates basic user profile info in LocalStorage
 */
export const updateUserProfileData = async (userId: string, data: Partial<UserData>): Promise<void> => {
  const users = getDb(USERS_DB_KEY);
  if (users[userId]) {
    users[userId] = { ...users[userId], ...data };
    saveDb(USERS_DB_KEY, users);
    await logActivity(userId, 'UPDATE_PROFILE', 'SUCCESS');
  } else {
      // Create if doesn't exist (fallback)
      users[userId] = { id: userId, ...data };
      saveDb(USERS_DB_KEY, users);
  }
};

/**
 * Updates notification preferences in LocalStorage
 */
export const updateUserPreferences = async (userId: string, prefsData: Partial<UserPreferences>): Promise<void> => {
  const prefs = getDb(PREFS_DB_KEY);
  if (!prefs[userId]) {
      prefs[userId] = { userId, contributions: true, payouts: true, updates: false };
  }
  prefs[userId] = { ...prefs[userId], ...prefsData };
  saveDb(PREFS_DB_KEY, prefs);
  await logActivity(userId, 'UPDATE_PREFS', 'SUCCESS');
};

/**
 * Saves the FCM Token to the user profile
 */
export const saveUserFcmToken = async (userId: string, token: string): Promise<void> => {
    const users = getDb(USERS_DB_KEY);
    if (users[userId]) {
        users[userId].fcmToken = token;
        saveDb(USERS_DB_KEY, users);
    }
};

