  // 1. Attempt to sign in
  const userCredential = await signInWithEmailAndPassword(auth, email, password);
  const user = userCredential.user;

  // 2. Check if email is verified
  if (!user.emailVerified) {
    // If not verified, sign them out immediately so session doesn't persist
    await signOut(auth);
    throw new Error('EMAIL_NOT_VERIFIED');
  }

  const userProfile = await mapAuthToUserData(user);

  return {
    user: userProfile,
    token: await user.getIdToken()
  };
};

export const register = async (name: string, email: string, password: string): Promise<void> => {
  // 1. Create User
  const userCredential = await createUserWithEmailAndPassword(auth, email, password);

  // 2. Update Firebase Auth Profile Name
  await updateProfile(userCredential.user, {
    displayName: name
  });

  // 3. Initialize User Data in our "Backend" (LocalStorage)
  await initializeUserDocuments({
      id: userCredential.user.uid,
      name: name,
      email: email,
      language: 'pt',
      lastLogin: new Date().toISOString()
  });

  // 4. Send Verification Email
  await sendEmailVerification(userCredential.user);

  // 5. Sign Out immediately (do not allow auto-login)
  await signOut(auth);
};

export const logout = async (): Promise<void> => {
  await signOut(auth);
};

