  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (isLogin) {
        await login(email, password);
        addToast('Welcome back!', 'success');
      } else {
        await register(name, email, password);
        addToast('Account created successfully!', 'success');
      }
    } catch (err: any) {
      console.error(err);
      // Map Firebase error codes to specific user messages
      let msg = 'Authentication failed. Please try again.';

      if (
        err.code === 'auth/invalid-credential' || 
        err.code === 'auth/wrong-password' || 
        err.code === 'auth/user-not-found' ||
        err.code === 'auth/invalid-email'
      ) {
          msg = "Email or password is incorrect";
      } else if (err.code === 'auth/email-already-in-use') {
          msg = "User already exists. Please sign in";
      } else if (err.code === 'auth/too-many-requests') {
          msg = "Too many attempts. Please try again later.";
      }

      addToast(msg, 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row font-sans bg-slate-50">

      {/* Left: Brand / Hero */}
      <div className="md:w-1/2 bg-slate-900 text-white p-8 md:p-16 flex flex-col justify-between relative overflow-hidden">
