  const logout = async () => {
    await apiLogout();
    setUser(null);
    localStorage.removeItem('xitique_mock_user');
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      login, 
      register, 
      logout,
      isAuthenticated: !!user 
