                        <div>
                            <div className="text-xs text-slate-400 font-bold uppercase">{t('detail.total_payout')}</div>
                            <div className="text-lg font-bold text-slate-900">
                                {formatCurrency(x.amount * x.participants.length)}
                            </div>
                        </div>
                        <div className={`w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center transition-colors group-hover:bg-slate-900 group-hover:text-white`}>
                            <ChevronRight size={16} />
                        </div>
                        </div>
                    </div>
                </div>
                );
            })}
            </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Xitique, XitiqueType, Frequency, PaymentMethod, TransactionType } from '../types';
import { getXitiques, saveXitique, createNewXitique, deleteXitique } from '../services/storage';
import { calculateBalance, createTransaction, validateTransaction } from '../services/financeLogic';
import { formatCurrency } from '../services/formatUtils';
import { PiggyBank, Plus, Smartphone, Banknote, Trash, X, ShieldAlert, Loader2 } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useToast } from '../contexts/ToastContext';
import FinancialTip from './FinancialTip';
import ConfirmationModal from './ConfirmationModal';

const IndividualDashboard: React.FC = () => {
  const { t } = useLanguage();
  const { addToast } = useToast();
  const [sticks, setSticks] = useState<Xitique[]>([]);
  const [isCreating, setIsCreating] = useState(false);
  const [loading, setLoading] = useState(true);

  // Withdrawal State
  const [withdrawStick, setWithdrawStick] = useState<Xitique | null>(null);
  const [withdrawAmount, setWithdrawAmount] = useState<number>(0);
  const [withdrawError, setWithdrawError] = useState<string>('');

  // Confirmation Modal State
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    type: 'danger' | 'success' | 'info';
    title: string;
    desc: string;
    action: () => void;
    confirmText?: string;
  }>({
    isOpen: false,
    type: 'info',
    title: '',
    desc: '',
    action: () => {}
  });

  // Form State
  const [name, setName] = useState('');
  const [targetAmount, setTargetAmount] = useState(5000);
  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.DAILY);
  const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.MPESA);

  const [expandedId, setExpandedId] = useState<string | null>(null);

  useEffect(() => {
    loadSticks();
  }, []);

  const loadSticks = async () => {
    setLoading(true);
    const all = await getXitiques();
    setSticks(all.filter(x => x.type === XitiqueType.INDIVIDUAL));
    setLoading(false);
  };

  const handleCreate = async () => {
    if (!name) {
        addToast(t('wiz.alert_name'), 'error');
        return;
    }

    const newStick = createNewXitique({
      name,
      type: XitiqueType.INDIVIDUAL,
      targetAmount,
      amount,
      frequency,
      method,
      startDate: new Date().toISOString(),
      participants: []
    });

    try {
        await saveXitique(newStick);
        addToast(t('common.success'), 'success');
        setIsCreating(false);
        loadSticks();
        setName('');
        setTargetAmount(5000);
        setAmount(100);
    } catch(err) {
        addToast('Failed to create', 'error');
    }
  };

  const requestDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setConfirmModal({
        isOpen: true,
        type: 'danger',
        title: t('modal.delete_title'),
        desc: t('modal.delete_desc'),
        confirmText: t('modal.confirm_delete'),
        action: async () => {
            await deleteXitique(id); 
            loadSticks();
            addToast('Item deletado', 'info');
        }
    });
  };

  const handleDeposit = async (stick: Xitique, e?: React.MouseEvent) => {
    if(e) e.stopPropagation();

    const validation = validateTransaction(stick, TransactionType.DEPOSIT, stick.amount);
    if (!validation.valid) {
        addToast(validation.error || 'Erro', 'error');
        return;
    }

    const newTx = createTransaction(
        TransactionType.DEPOSIT,
        stick.amount,
        t('ind.type_deposit')
    );

    const updated = {
      ...stick,
      transactions: [newTx, ...(stick.transactions || [])]
    };

    await saveXitique(updated);
    addToast(t('ind.type_deposit') + ' ' + t('common.success'), 'success');
    loadSticks();
  };

  const handleWithdraw = async () => {
    if(!withdrawStick) return;

    const validation = validateTransaction(withdrawStick, TransactionType.WITHDRAWAL, withdrawAmount);
    if (!validation.valid) {
        setWithdrawError(validation.error || "Error");
        return;
    }

    const newTx = createTransaction(
        TransactionType.WITHDRAWAL,
        withdrawAmount,
        t('ind.type_withdrawal')
    );

    const updated = {
        ...withdrawStick,
        transactions: [newTx, ...(withdrawStick.transactions || [])]
    };

    await saveXitique(updated);
    setWithdrawStick(null);
    setWithdrawAmount(0);
    setWithdrawError('');
    addToast(t('ind.type_withdrawal') + ' ' + t('common.success'), 'success');
    loadSticks();
  };

  const getMethodIcon = (m?: PaymentMethod) => {
    switch (m) {
      case PaymentMethod.MPESA: return <span className="bg-red-100 text-red-700 border border-red-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> M-Pesa</span>;
      case PaymentMethod.EMOLA: return <span className="bg-orange-100 text-orange-700 border border-orange-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Smartphone size={12}/> e-Mola</span>;
      default: return <span className="bg-emerald-100 text-emerald-700 border border-emerald-200 px-2 py-1 rounded text-[10px] font-bold flex items-center gap-1 uppercase tracking-wide"><Banknote size={12}/> Cash</span>;
    }
  };

  const getFrequencyLabel = (f: Frequency) => {
    switch (f) {
      case Frequency.DAILY: return t('ind.daily');
      case Frequency.WEEKLY: return t('ind.weekly');
      default: return t('ind.monthly');
    }
  };

  const getProjectedDate = (stick: Xitique, balance: number) => {
    if (balance <= 0) return null;
    const start = new Date(stick.createdAt);
    const now = new Date();
    const daysSinceStart = Math.max(1, Math.floor((now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)));

    const ratePerDay = balance / daysSinceStart;
    if (ratePerDay <= 0) return null;

    const remaining = (stick.targetAmount || 0) - balance;
    if (remaining <= 0) return new Date(); 

    const daysLeft = Math.ceil(remaining / ratePerDay);
    const projectedDate = new Date();
    projectedDate.setDate(projectedDate.getDate() + daysLeft);
    return projectedDate;
  };

  if (isCreating) {
    return (
       <div className="max-w-xl mx-auto bg-white p-8 rounded-3xl shadow-xl border border-slate-200 animate-fade-in my-8">
        <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <PiggyBank className="text-purple-500" /> {t('ind.create_btn')}
            </h2>
            <button onClick={() => setIsCreating(false)} className="p-2 bg-slate-100 rounded-full hover:bg-slate-200 text-slate-500">
                <X size={20} />
            </button>
        </div>

        <div className="space-y-6">
            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_name')}</label>
                <input 
                    type="text" 
                    value={name} 
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Ex: Novo Telefone"
                    className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none transition-all font-medium"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_target')}</label>
                    <div className="relative">
                        <span className="absolute left-3 top-3.5 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                        <input 
                            type="number" 
                            value={targetAmount} 
                            onChange={(e) => setTargetAmount(Number(e.target.value))}
                            className="w-full p-3 pl-10 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none font-mono"
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_contribution')}</label>
                    <div className="relative">
                        <span className="absolute left-3 top-3.5 text-slate-400 text-xs font-bold">{t('common.currency')}</span>
                        <input 
                            type="number" 
                            value={amount} 
                            onChange={(e) => setAmount(Number(e.target.value))}
                            className="w-full p-3 pl-10 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none font-mono"
                        />
                    </div>
                </div>
            </div>

            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_freq')}</label>
                <div className="grid grid-cols-3 gap-2">
                    {[Frequency.DAILY, Frequency.WEEKLY, Frequency.MONTHLY].map(f => (
                        <button
                            key={f}
                            onClick={() => setFrequency(f)}
                            className={`py-2 px-1 rounded-lg text-xs font-bold border transition-all ${
                                frequency === f 
                                ? 'bg-purple-600 text-white border-purple-600' 
                                : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                            }`}
                        >
                            {getFrequencyLabel(f)}
                        </button>
                    ))}
                </div>
            </div>

            <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('ind.form_method')}</label>
                <div className="grid grid-cols-3 gap-2">
                    {[
                        { id: PaymentMethod.MPESA, label: 'M-Pesa', icon: Smartphone },
                        { id: PaymentMethod.EMOLA, label: 'e-Mola', icon: Smartphone },
                        { id: PaymentMethod.CASH, label: 'Cash', icon: Banknote },
                    ].map(m => (
                        <button
                            key={m.id}
                            onClick={() => setMethod(m.id)}
                            className={`py-3 px-2 rounded-xl text-xs font-bold border flex flex-col items-center gap-1 transition-all ${
                                method === m.id
                                ? 'bg-slate-900 text-white border-slate-900' 
                                : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                            }`}
                        >
                            <m.icon size={16} />
                            {m.label}
                        </button>
                    ))}
                </div>
            </div>

            <button 
                onClick={handleCreate}
                className="w-full py-4 bg-purple-600 hover:bg-purple-700 text-white font-bold rounded-xl shadow-lg shadow-purple-200 transition-all mt-4"
            >
                {t('ind.create_btn')}
            </button>
        </div>
      </div>
    );
  }

  if (loading) {
     return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-purple-500" /></div>;
  }

  return (
    <div className="space-y-8 animate-fade-in pb-12">
        {/* Confirmation Modal */}
        <ConfirmationModal 
            isOpen={confirmModal.isOpen}
            onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            onConfirm={confirmModal.action}
            title={confirmModal.title}
            description={confirmModal.desc}
            type={confirmModal.type}
            confirmText={confirmModal.confirmText}
        />

        {/* Withdrawal Modal */}
        {withdrawStick && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                <div className="bg-white rounded-3xl p-6 max-w-sm w-full shadow-2xl animate-fade-in">
                    <h3 className="text-xl font-bold text-slate-900 mb-2">{t('ind.withdraw_modal_title')}</h3>
                    <p className="text-slate-500 text-sm mb-4">{t('ind.withdraw_modal_desc')}</p>

                    <div className="mb-4">
                      <FinancialTip context="withdrawal" />
                    </div>

                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mb-4">
                        <div className="text-xs text-slate-400 font-bold uppercase">{t('ind.balance')}</div>
                        <div className="text-xl font-bold text-slate-900">{formatCurrency(calculateBalance(withdrawStick.transactions))}</div>
                    </div>

                    <label className="block text-xs font-bold text-slate-700 mb-1">Amount</label>
                    <input 
                        type="number" 
                        value={withdrawAmount} 
                        onChange={(e) => setWithdrawAmount(Number(e.target.value))}
                        className="w-full p-3 border border-slate-300 rounded-xl mb-2 font-bold text-lg"
                    />
                    {withdrawError && <p className="text-red-500 text-xs font-bold mb-4 flex items-center gap-1"><ShieldAlert size={12}/> {withdrawError}</p>}

                    <div className="flex gap-2">
                        <button 
                            onClick={() => { setWithdrawStick(null); setWithdrawError(''); }}
                            className="flex-1 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold rounded-xl"
                        >
                            {t('ind.withdraw_cancel')}
                        </button>
                        <button 
                            onClick={handleWithdraw}
                            className="flex-1 py-3 bg-slate-900 hover:bg-slate-800 text-white font-bold rounded-xl"
                        >
                            {t('ind.withdraw_confirm')}
                        </button>
                    </div>
                </div>
            </div>
        )}

        <div className="flex justify-between items-center">
            <div>
                <h1 className="text-3xl font-bold text-slate-900 tracking-tight">{t('ind.title')}</h1>
                <p className="text-slate-500 mt-1">{t('ind.subtitle')}</p>
            </div>
            <button 
                onClick={() => setIsCreating(true)}
                className="bg-purple-600 hover:bg-purple-700 text-white px-4 py-2 md:px-6 md:py-3 rounded-xl font-bold shadow-lg shadow-purple-200 transition-all flex items-center gap-2"
            >
                <Plus size={20} /> <span className="hidden md:inline">{t('ind.create_btn')}</span>
            </button>
        </div>

        {sticks.length > 0 && (
           <FinancialTip context="individual" />
        )}

        {sticks.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-300 shadow-sm">
                <div className="w-20 h-20 bg-purple-50 rounded-full flex items-center justify-center mx-auto mb-6 text-purple-400">
                    <PiggyBank size={40} />
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">{t('ind.no_active')}</h3>
                <p className="text-slate-500 mb-8 max-w-sm mx-auto">{t('ind.start_desc')}</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {sticks.map(stick => {
                    const balance = calculateBalance(stick.transactions);
                    const target = stick.targetAmount || 1;
                    const progress = Math.min(100, (balance / target) * 100);
                    const remaining = Math.max(0, target - balance);
                    const estimatedPeriods = Math.ceil(remaining / stick.amount);
                    const isExpanded = expandedId === stick.id;
                    const projectedDate = getProjectedDate(stick, balance);

                    return (
                        <div 
                            key={stick.id} 
                            onClick={() => setExpandedId(isExpanded ? null : stick.id)}
                            className={`bg-white rounded-2xl p-6 border transition-all cursor-pointer ${isExpanded ? 'border-purple-300 shadow-xl ring-2 ring-purple-50 col-span-1 md:col-span-2' : 'border-slate-200 shadow-sm hover:shadow-lg'}`}
                        >
                            {/* Header */}
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <h3 className="text-lg font-bold text-slate-900">{stick.name}</h3>
                                        {getMethodIcon(stick.method)}
                                    </div>
                                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">
                                        {getFrequencyLabel(stick.frequency)} • {formatCurrency(stick.amount)}
                                    </p>
                                </div>
                                <button onClick={(e) => requestDelete(stick.id, e)} className="text-slate-300 hover:text-red-500 transition-colors p-2">
                                    <Trash size={18} />
                                </button>
                            </div>

                            {/* Main Balance Display */}
                            <div className="mb-4">
                                <div className="flex justify-between items-end mb-2">
                                    <div className="text-3xl font-bold text-slate-900">{formatCurrency(balance)}</div>
                                    <div className="text-xs font-bold text-slate-500">{Math.round(progress)}% of {formatCurrency(target)}</div>
                                </div>
                                <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
                                    <div className="bg-purple-500 h-3 rounded-full transition-all duration-1000" style={{ width: `${progress}%` }}></div>
                                </div>
                            </div>

                            {/* Actions & Insights */}
                            <div className="grid grid-cols-2 gap-3 mb-4">
                                <button 
                                    onClick={(e) => handleDeposit(stick, e)}
                                    className="bg-emerald-50 text-emerald-700 hover:bg-emerald-100 py-3 rounded-xl font-bold text-sm transition-colors flex items-center justify-center gap-2 border border-emerald-100"
                                >
                                    <Plus size={16} /> {t('ind.deposit')}
                                </button>
                                <button 
                                    onClick={(e) => { e.stopPropagation(); setWithdrawStick(stick); }}
                                    className="bg-slate-50 text-slate-700 hover:bg-slate-100 py-3 rounded-xl font-bold text-sm transition-colors border border-slate-100"
                                >
                                    {t('ind.withdraw')}
                                </button>
                            </div>

                            {/* Details (Expanded View) */}
                            {isExpanded && (
                                <div className="border-t border-slate-100 pt-4 mt-4 animate-fade-in">
                                     <div className="grid md:grid-cols-2 gap-6">
                                         <div>
                                            <h4 className="text-xs font-bold text-slate-400 uppercase mb-3">{t('ind.timeline')}</h4>
                                            <ul className="space-y-4 relative pl-4 border-l-2 border-slate-100">
                                                <li className="relative">
                                                    <div className="absolute -left-[21px] top-1 w-3 h-3 rounded-full bg-purple-500 ring-4 ring-white"></div>
                                                    <div className="text-sm font-bold text-slate-800">{t('ind.timeline_start')}</div>
                                                    <div className="text-xs text-slate-500">{new Date(stick.createdAt).toLocaleDateString()}</div>
                                                </li>
                                                <li className="relative">
                                                     <div className="absolute -left-[21px] top-1 w-3 h-3 rounded-full bg-slate-300 ring-4 ring-white"></div>
                                                     <div className="text-sm font-bold text-slate-800">{t('ind.remaining')}</div>
                                                     <div className="text-xs text-slate-500">{formatCurrency(remaining)} ({estimatedPeriods} {stick.frequency === 'DAILY' ? t('ind.days') : stick.frequency === 'WEEKLY' ? t('ind.weeks') : t('ind.months')})</div>
                                                </li>
                                                <li className="relative">
                                                     <div className="absolute -left-[21px] top-1 w-3 h-3 rounded-full bg-emerald-400 ring-4 ring-white"></div>
                                                     <div className="text-sm font-bold text-emerald-700">{t('ind.timeline_projected')}</div>
                                                     <div className="text-xs text-emerald-600 font-bold">
                                                        {projectedDate ? projectedDate.toLocaleDateString() : t('ind.timeline_unknown')}
                                                     </div>
                                                </li>
                                            </ul>
                                         </div>

                                         <div>
                                            <h4 className="text-xs font-bold text-slate-400 uppercase mb-3">{t('ind.history')}</h4>
                                            <div className="max-h-40 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                                                {stick.transactions && stick.transactions.length > 0 ? (
                                                    stick.transactions.map((tx) => (
                                                        <div key={tx.id} className="flex justify-between items-center text-sm p-2 bg-slate-50 rounded-lg">
                                                            <div className="flex items-center gap-2">
                                                                <span className={`w-2 h-2 rounded-full ${tx.type === TransactionType.DEPOSIT ? 'bg-emerald-500' : 'bg-red-500'}`}></span>
                                                                <span className="text-slate-600">{tx.description}</span>
                                                            </div>
                                                            <div className={`font-bold ${tx.type === TransactionType.DEPOSIT ? 'text-emerald-600' : 'text-slate-900'}`}>
                                                                {tx.type === TransactionType.WITHDRAWAL ? '-' : '+'}{formatCurrency(tx.amount)}
                                                            </div>
                                                        </div>
                                                    ))
                                                ) : (
                                                    <div className="text-slate-400 text-xs text-center py-4 italic">No transactions yet</div>
                                                )}
                                            </div>
                                         </div>
                                     </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        )}
    </div>
  );
};

export default IndividualDashboard;

import React, { useState, useEffect } from 'react';
import { Frequency, Xitique, PaymentMethod } from '../types';
import { createNewXitique, saveXitique } from '../services/storage';
import { addPeriod, formatDate } from '../services/dateUtils';
import { ChevronRight, ChevronLeft, Check, UserPlus, Trash2, ArrowUp, ArrowDown, Calendar, GripVertical, Lock, Unlock, Smartphone, Banknote, RefreshCw, Loader2 } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useToast } from '../contexts/ToastContext';

interface WizardProps {
  onComplete: () => void;
  onCancel: () => void;
  initialData?: Xitique | null; 
}

const Wizard: React.FC<WizardProps> = ({ onComplete, onCancel, initialData }) => {
  const { t } = useLanguage();
  const { addToast } = useToast();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [name, setName] = useState('');
  const [amount, setAmount] = useState(100);
  const [frequency, setFrequency] = useState<Frequency>(Frequency.MONTHLY);
  const [method, setMethod] = useState<PaymentMethod>(PaymentMethod.MPESA);
  const [startDate, setStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [participantNames, setParticipantNames] = useState<string[]>(['', '']);

  const [orderedParticipants, setOrderedParticipants] = useState<string[]>([]);
  const [lockedIndices, setLockedIndices] = useState<Set<number>>(new Set());

  // Initialization Logic for Renewal
  useEffect(() => {
    if (initialData) {
        setName(`${initialData.name} (Cycle 2)`);
        setAmount(initialData.amount);
        setFrequency(initialData.frequency);
        if(initialData.method) setMethod(initialData.method);

        // Extract names from previous participants
        const names = initialData.participants.map(p => p.name);
        setParticipantNames(names);

        // Ensure start date is today or future, not old date
        setStartDate(new Date().toISOString().split('T')[0]);
    }
  }, [initialData]);

  useEffect(() => {
    if (step === 3 && orderedParticipants.length === 0) {
        setOrderedParticipants(participantNames.filter(n => n.trim() !== ''));
    }
  }, [step, participantNames]);

  const handleAddParticipant = () => {
    setParticipantNames([...participantNames, '']);
  };

  const handleRemoveParticipant = (index: number) => {
    const newNames = [...participantNames];
    newNames.splice(index, 1);
    setParticipantNames(newNames);
  };

  const handleNameChange = (index: number, val: string) => {
    const newNames = [...participantNames];
    newNames[index] = val;
    setParticipantNames(newNames);
  };

  const toggleLock = (index: number) => {
    const newSet = new Set(lockedIndices);
    if (newSet.has(index)) {
        newSet.delete(index);
    } else {
        newSet.add(index);
    }
    setLockedIndices(newSet);
  };

  const moveParticipant = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...orderedParticipants];
    const newLocked = new Set(lockedIndices);

    const swap = (i1: number, i2: number) => {
        [newOrder[i1], newOrder[i2]] = [newOrder[i2], newOrder[i1]];
        const locked1 = newLocked.has(i1);
        const locked2 = newLocked.has(i2);

        if (locked1) { newLocked.delete(i1); newLocked.add(i2); }
        if (locked2) { newLocked.delete(i2); newLocked.add(i1); }
    };

    if (direction === 'up' && index > 0) {
        swap(index, index - 1);
    } else if (direction === 'down' && index < newOrder.length - 1) {
        swap(index, index + 1);
    }
    setOrderedParticipants(newOrder);
    setLockedIndices(newLocked);
  };

  const handleFinish = async () => {
    setLoading(true);
    // Generate NEW IDs for participants to ensure no reference linking to old cycle
    const participants = orderedParticipants.map((pName, index) => ({
      id: crypto.randomUUID(),
      name: pName,
      received: false,
      order: index + 1,
      payoutDate: addPeriod(startDate, frequency, index)
    }));

    const newXitique = createNewXitique({
      name,
      amount,
      frequency,
      method,
      startDate: new Date(startDate).toISOString(),
      participants
    });

    try {
        await saveXitique(newXitique);
        addToast(t('common.success'), 'success');
        onComplete();
    } catch (err) {
        console.error(err);
        addToast('Failed to save. Please try again.', 'error');
        setLoading(false);
    }
  };

  const isRenewal = !!initialData;

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden max-w-4xl mx-auto border border-slate-200 font-sans">
      {/* Header */}
      <div className={`${isRenewal ? 'bg-indigo-900' : 'bg-slate-900'} p-8 text-white flex justify-between items-center relative overflow-hidden transition-colors`}>
        <div className="relative z-10">
          <div className="flex items-center gap-3">
              {isRenewal && <RefreshCw size={24} className="text-emerald-400" />}
              <h2 className="text-3xl font-bold tracking-tight">{isRenewal ? t('wiz.title_renew') : t('wiz.title')}</h2>
          </div>
          <p className="text-slate-400 text-sm mt-1">{t('wiz.subtitle')}</p>
        </div>

        {/* Progress Dots */}
        <div className="flex space-x-3 relative z-10">
          {[1, 2, 3, 4].map((s) => (
             <div 
                key={s} 
                className={`transition-all duration-500 ${step === s ? 'w-10 bg-emerald-400' : step > s ? 'w-3 bg-emerald-800' : 'w-3 bg-slate-700'} h-3 rounded-full`} 
             />
          ))}
        </div>

        {/* Abstract Deco */}
        <div className="absolute right-0 top-0 h-full w-1/3 bg-emerald-500/10 transform -skew-x-12 translate-x-10"></div>
      </div>

      <div className="p-8 md:p-10 bg-slate-50/50">

        {/* STEP 1: BASICS */}
        {step === 1 && (
          <div className="space-y-8 animate-fade-in">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <h3 className="text-xl font-bold text-slate-900 mb-6 flex items-center gap-2">
                    <span className={`w-8 h-8 rounded-full ${isRenewal ? 'bg-indigo-900' : 'bg-slate-900'} text-white flex items-center justify-center text-sm`}>1</span>
                    {t('wiz.step1')}
                </h3>

                <div className="group mb-6">
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('wiz.label_name')}</label>
                <input 
                    type="text" 
                    value={name} 
                    onChange={(e) => setName(e.target.value)}
                    placeholder={t('wiz.placeholder_name')}
                    className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                    autoFocus
                />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('wiz.label_amount')}</label>
                    <div className="relative">
                    <span className="absolute left-4 top-4 text-slate-400 font-bold">{t('common.currency')}</span>
                    <input 
                        type="number" 
                        value={amount} 
                        onChange={(e) => setAmount(Number(e.target.value))}
                        className="w-full p-4 pl-12 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all font-mono text-lg"
                    />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('wiz.label_freq')}</label>
                    <div className="grid grid-cols-3 gap-2">
                    <button 
                        onClick={() => setFrequency(Frequency.WEEKLY)}
                        className={`py-4 px-2 rounded-xl text-xs font-bold transition-all border ${frequency === Frequency.WEEKLY ? 'bg-slate-900 text-emerald-400 border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'}`}
                    >
                        {t('wiz.weekly')}
                    </button>
                    <button 
                        onClick={() => setFrequency(Frequency.MONTHLY)}
                        className={`py-4 px-2 rounded-xl text-xs font-bold transition-all border ${frequency === Frequency.MONTHLY ? 'bg-slate-900 text-emerald-400 border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'}`}
                    >
                        {t('wiz.monthly')}
                    </button>
                    <button 
                        onClick={() => setFrequency(Frequency.DAILY)}
                        className={`py-4 px-2 rounded-xl text-xs font-bold transition-all border ${frequency === Frequency.DAILY ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400'}`}
                    >
                        {t('wiz.daily')}
                    </button>
                    </div>
                </div>
                </div>

                <div className="mb-6">
                   <label className="block text-sm font-bold text-slate-700 mb-2">{t('wiz.label_method')}</label>
                   <div className="grid grid-cols-3 gap-2">
                    {[
                        { id: PaymentMethod.MPESA, label: 'M-Pesa', icon: Smartphone },
                        { id: PaymentMethod.EMOLA, label: 'e-Mola', icon: Smartphone },
                        { id: PaymentMethod.CASH, label: 'Cash', icon: Banknote },
                    ].map(m => (
                        <button
                            key={m.id}
                            onClick={() => setMethod(m.id)}
                            className={`py-3 px-2 rounded-xl text-xs font-bold border flex flex-col items-center gap-1 transition-all ${
                                method === m.id
                                ? 'bg-slate-900 text-white border-slate-900' 
                                : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                            }`}
                        >
                            <m.icon size={16} />
                            {m.label}
                        </button>
                    ))}
                  </div>
                </div>

                <div>
                <label className="block text-sm font-bold text-slate-700 mb-2">{t('wiz.label_start')}</label>
                <input 
                    type="date" 
                    value={startDate} 
                    onChange={(e) => setStartDate(e.target.value)}
                    className="w-full p-4 border border-slate-200 bg-slate-50 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
                />
                </div>
            </div>
          </div>
        )}

        {/* STEP 2: PARTICIPANTS */}
        {step === 2 && (
          <div className="space-y-6 animate-fade-in">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <h3 className="text-xl font-bold text-slate-900 mb-2 flex items-center gap-2">
                    <span className={`w-8 h-8 rounded-full ${isRenewal ? 'bg-indigo-900' : 'bg-slate-900'} text-white flex items-center justify-center text-sm`}>2</span>
                    {t('wiz.step2')}
                </h3>
                <p className="text-sm text-slate-500 mb-6 ml-10">
                    {t('wiz.add_member_desc')}
                </p>

                <div className="max-h-[400px] overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                {participantNames.map((pName, idx) => (
                    <div key={idx} className="flex items-center gap-3 animate-fade-in">
                    <span className="bg-slate-100 text-slate-400 w-10 h-10 flex items-center justify-center rounded-xl text-sm font-bold border border-slate-200">
                        {idx + 1}
                    </span>
                    <input
                        type="text"
                        placeholder={t('wiz.placeholder_member')}
                        value={pName}
                        onChange={(e) => handleNameChange(idx, e.target.value)}
                        className="flex-1 p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                        autoFocus={idx === participantNames.length - 1 && idx > 0}
                    />
                    {participantNames.length > 2 && (
                        <button onClick={() => handleRemoveParticipant(idx)} className="text-slate-300 hover:text-red-500 transition-colors p-2">
                        <Trash2 size={20} />
                        </button>
                    )}
                    </div>
                ))}
                </div>

                <button 
                onClick={handleAddParticipant}
                className="w-full py-4 border-2 border-dashed border-slate-300 rounded-xl flex items-center justify-center text-slate-500 font-bold hover:border-emerald-500 hover:text-emerald-600 hover:bg-emerald-50 transition-all mt-4"
                >
                <UserPlus size={18} className="mr-2" /> {t('wiz.btn_add_member')}
                </button>
            </div>
          </div>
        )}

        {/* STEP 3: ORDERING (ALGORITHM OF JUSTICE) */}
        {step === 3 && (
            <div className="space-y-6 animate-fade-in">
                <div className="flex items-center justify-between">
                    <div>
                        <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                            <span className={`w-8 h-8 rounded-full ${isRenewal ? 'bg-indigo-900' : 'bg-slate-900'} text-white flex items-center justify-center text-sm`}>3</span>
                            {t('wiz.algo_title')}
                        </h3>
                        <p className="text-sm text-slate-500 mt-1 ml-10">{t('wiz.algo_desc')}</p>
                    </div>
                </div>

                <div className="space-y-3 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                    {orderedParticipants.map((pName, idx) => {
                        const calculatedDate = addPeriod(startDate, frequency, idx);
                        const isLast = idx === orderedParticipants.length - 1;
                        const isFirst = idx === 0;
                        const isLocked = lockedIndices.has(idx);

                        return (
                            <div 
                                key={idx} 
                                className={`flex items-center gap-4 border p-4 rounded-xl transition-all duration-300 group ${
                                    isLocked 
                                        ? 'bg-rose-50 border-rose-200 shadow-md transform scale-[1.01]' 
                                        : 'bg-white border-slate-100 hover:border-emerald-300 hover:shadow-md'
                                }`}
                            >
                                <div className={`cursor-grab ${isLocked ? 'text-rose-400' : 'text-slate-300'}`}>
                                    <GripVertical size={20} />
                                </div>

                                <div className="flex-1">
                                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-2">
                                        <div className="flex items-center gap-3">
                                            <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${isLocked ? 'bg-rose-200 text-rose-700' : 'bg-slate-100 text-slate-500'}`}>
                                                {idx + 1}
                                            </span>
                                            <span className={`font-bold text-lg ${isLocked ? 'text-rose-700' : 'text-slate-800'}`}>
                                                {pName}
                                            </span>
                                        </div>

                                        <div className={`flex items-center text-sm font-semibold px-3 py-1.5 rounded-lg ${isLocked ? 'bg-rose-200 text-rose-800' : 'bg-emerald-50 text-emerald-700'}`}>
                                            <Calendar size={14} className="mr-2" />
                                            {formatDate(calculatedDate)}
                                        </div>
                                    </div>
                                </div>

                                {/* Lock Control */}
                                <button 
                                    onClick={() => toggleLock(idx)}
                                    className={`p-2 rounded-lg transition-colors ${
                                        isLocked 
                                        ? 'bg-rose-100 text-rose-600 hover:bg-rose-200' 
                                        : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-500'
                                    }`}
                                    title={isLocked ? t('wiz.unlock') : t('wiz.lock')}
                                >
                                    {isLocked ? <Lock size={18} /> : <Unlock size={18} />}
                                </button>

                                {/* Movement Controls */}
                                <div className="flex flex-col gap-1">
                                    <button 
                                        onClick={() => moveParticipant(idx, 'up')}
                                        disabled={isFirst}
                                        className={`p-1 rounded hover:bg-slate-100 ${isFirst ? 'text-slate-200' : 'text-slate-400 hover:text-emerald-600'}`}
                                    >
                                        <ArrowUp size={18} />
                                    </button>
                                    <button 
                                        onClick={() => moveParticipant(idx, 'down')}
                                        disabled={isLast}
                                        className={`p-1 rounded hover:bg-slate-100 ${isLast ? 'text-slate-200' : 'text-slate-400 hover:text-emerald-600'}`}
                                    >
                                        <ArrowDown size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}

        {/* STEP 4: REVIEW */}
        {step === 4 && (
          <div className="animate-fade-in text-center py-8">
            <div className="w-24 h-24 bg-emerald-100 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-xl shadow-emerald-100/50">
              <Check size={48} strokeWidth={3} />
            </div>
            <h3 className="text-3xl font-bold text-slate-900 mb-3">{t('wiz.system_ready')}</h3>
            <p className="text-slate-500 mb-8 max-w-md mx-auto leading-relaxed">
              {t('wiz.ready_desc')}
              <br />
              <span className="text-slate-400 text-sm">{t('wiz.total_pot')}</span> <strong className="text-emerald-600 text-2xl">{t('common.currency')} {amount * participantNames.filter(n => n).length}</strong>
            </p>

            <div className="bg-white border border-slate-200 p-8 rounded-2xl text-left shadow-sm max-w-lg mx-auto">
               <h4 className="font-bold text-slate-900 mb-4 border-b border-slate-100 pb-2">{t('wiz.summary')}</h4>
               <ul className="space-y-4 text-sm">
                 <li className="flex justify-between items-center">
                    <span className="text-slate-500">{t('wiz.first_payout')}</span>
                    <span className="font-bold text-slate-900 bg-slate-50 px-2 py-1 rounded">{orderedParticipants[0]}</span>
                 </li>
                 <li className="flex justify-between items-center">
                    <span className="text-slate-500">{t('wiz.last_payout')}</span>
                    <span className="font-bold text-slate-900 bg-slate-50 px-2 py-1 rounded">{orderedParticipants[orderedParticipants.length-1]}</span>
                 </li>
                 <li className="flex justify-between items-center">
                    <span className="text-slate-500">{t('wiz.locked_dates')}</span>
                    <span className={`font-bold px-2 py-1 rounded ${lockedIndices.size > 0 ? 'bg-rose-100 text-rose-700' : 'bg-slate-50 text-slate-900'}`}>{lockedIndices.size} {t('wiz.members_count')}</span>
                 </li>
               </ul>
            </div>
          </div>
        )}

        {/* Footer Actions */}
        <div className="flex justify-between mt-10 pt-6 border-t border-slate-200">
          {step === 1 ? (
            <button onClick={onCancel} className="text-slate-400 font-semibold hover:text-slate-600 px-4">
              {t('wiz.btn_cancel')}
            </button>
          ) : (
            <button onClick={() => setStep(step - 1)} className="flex items-center text-slate-500 font-semibold hover:text-slate-800 px-4">
              <ChevronLeft size={20} className="mr-1" /> {t('wiz.btn_back')}
            </button>
          )}

          {step < 4 ? (
            <button 
              onClick={() => {
                if(step === 1 && !name) { addToast(t('wiz.alert_name'), 'error'); return; }
                if(step === 2) {
                     const valid = participantNames.filter(n => n.trim() !== '');
                     if (valid.length < 2) { addToast(t('wiz.alert_members'), 'error'); return; }
                     if (valid.length !== orderedParticipants.length) {
                         setOrderedParticipants(valid);
                     }
                }
                setStep(step + 1)
              }} 
              className={`${isRenewal ? 'bg-indigo-900 hover:bg-indigo-800' : 'bg-slate-900 hover:bg-slate-800'} text-white px-8 py-4 rounded-xl font-semibold flex items-center shadow-xl shadow-slate-200 transition-all transform hover:-translate-y-1`}
            >
              {t('wiz.btn_next')} <ChevronRight size={20} className="ml-1" />
            </button>
          ) : (
            <button 
              onClick={handleFinish} 
              disabled={loading}
              className="bg-emerald-500 hover:bg-emerald-600 text-white px-10 py-4 rounded-xl font-bold flex items-center shadow-xl shadow-emerald-200 transition-all transform hover:-translate-y-1 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin mr-2" /> : null}
              {isRenewal ? t('wiz.btn_launch_renew') : t('wiz.btn_launch')}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Wizard;

import React, { useState, useEffect } from 'react';
import { Xitique, Participant, TransactionType, XitiqueStatus } from '../types';
import { formatDate } from '../services/dateUtils';
import { formatCurrency } from '../services/formatUtils';
import { analyzeFairness } from '../services/geminiService';
import { saveXitique } from '../services/storage';
import { createTransaction, calculateCyclePot } from '../services/financeLogic';
import { Sparkles, Calendar, DollarSign, Users, ArrowLeft, Trash, CheckCircle2, Clock, Pencil, X, Check, History, Calculator, AlertTriangle, AlertCircle, RefreshCw, Archive, Share2, Loader2 } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useToast } from '../contexts/ToastContext';
import FinancialTip from './FinancialTip';
import ConfirmationModal from './ConfirmationModal';

interface Props {
  xitique: Xitique;
  onBack: () => void;
  onDelete: () => void;
  onRenew?: (xitique: Xitique) => void;
}

const XitiqueDetail: React.FC<Props> = ({ xitique, onBack, onDelete, onRenew }) => {
  const { t } = useLanguage();
  const { addToast } = useToast();
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [activeTab, setActiveTab] = useState<'schedule' | 'analysis' | 'history'>('schedule');

  // Edit State (Global)
  const [isEditingBase, setIsEditingBase] = useState(false);
  const [newBaseAmount, setNewBaseAmount] = useState(xitique.amount);

  // Edit State (Individual)
  const [editingParticipantId, setEditingParticipantId] = useState<string | null>(null);
  const [individualAmount, setIndividualAmount] = useState<number>(0);

  // Derived State
  const potSize = calculateCyclePot(xitique.amount, xitique.participants);
  const hasUnequalContributions = xitique.participants.some(p => p.customContribution !== undefined && p.customContribution !== xitique.amount);
  const progressPercentage = (xitique.participants.filter(p => p.received).length / xitique.participants.length) * 100;
  const isCompleted = xitique.status === XitiqueStatus.COMPLETED;

  // Modal State
  const [confirmModal, setConfirmModal] = useState<{
    isOpen: boolean;
    type: 'danger' | 'success' | 'info';
    title: string;
    desc: string;
    action: () => void;
    confirmText?: string;
  }>({
    isOpen: false,
    type: 'info',
    title: '',
    desc: '',
    action: () => {}
  });

  useEffect(() => {
    setNewBaseAmount(xitique.amount);
  }, [xitique.amount]);

  // --- Logic ---

  const handleShare = async () => {
    try {
        const header = `💰 *${xitique.name}*`;
        const pot = `💵 *Pote:* ${formatCurrency(potSize)}`;
        const list = xitique.participants.map((p, i) => {
            const date = p.payoutDate ? formatDate(p.payoutDate) : 'TBD';
            const status = p.received ? '✅ Pago' : '⏳ Pendente';
            return `${i + 1}. ${p.name} - ${date} (${status})`;
        }).join('\n');

        const footer = `\nGerado por Xitique Xanga`;
        const fullText = `${header}\n${pot}\n\n📅 *Cronograma:*\n${list}${footer}`;

        await navigator.clipboard.writeText(fullText);
        addToast(t('detail.share_success'), 'success');
    } catch (err) {
        addToast(t('detail.share_fail'), 'error');
    }
  };

  const handleRunAnalysis = async () => {
    setLoadingAi(true);
    addToast('Iniciando análise com Gemini...', 'info');
    const result = await analyzeFairness(xitique);
    setAiAnalysis(result);
    setLoadingAi(false);
  };

  const handleRecalculate = async () => {
      const updatedXitique = { 
          ...xitique, 
          status: hasUnequalContributions ? XitiqueStatus.RISK : XitiqueStatus.ACTIVE 
      };
      await saveXitique(updatedXitique);
      if(updatedXitique.status === XitiqueStatus.RISK) {
          xitique.status = XitiqueStatus.RISK; 
      }
      addToast(t('detail.recalc_title') + ': ' + t('common.success'), 'success');
  };

  const handleToggleClick = (participantId: string) => {
    if(isCompleted) return;

    const participant = xitique.participants.find(p => p.id === participantId);
    if (!participant) return;

    if (!participant.received) {
        setConfirmModal({
            isOpen: true,
            type: 'success',
            title: `${t('modal.payout_title')}: ${participant.name}`,
            desc: `${t('modal.payout_desc')} (${formatCurrency(potSize)})`,
            confirmText: t('modal.confirm_payout'),
            action: () => executeToggle(participantId)
        });
    } else {
        setConfirmModal({
            isOpen: true,
            type: 'danger',
            title: t('modal.reversal_title'),
            desc: t('modal.reversal_desc'),
            confirmText: t('modal.confirm_reversal'),
            action: () => executeToggle(participantId)
        });
    }
  };

  const executeToggle = async (participantId: string) => {
    const participant = xitique.participants.find(p => p.id === participantId);
    if (!participant) return;

    const willReceive = !participant.received;

    let newTx;
    if (willReceive) {
        newTx = createTransaction(
            TransactionType.PAYOUT,
            potSize, 
            `${t('ind.type_payout')}: ${participant.name}`
        );
    } else {
        newTx = createTransaction(
            TransactionType.PAYOUT_REVERSAL,
            potSize,
            `Correction (Reversal): ${participant.name}`
        );
    }

    const updatedTx = [newTx, ...(xitique.transactions || [])];

    const updatedParticipants = xitique.participants.map(p => 
      p.id === participantId ? { ...p, received: willReceive } : p
    );

    const allReceived = updatedParticipants.every(p => p.received);

    const updatedXitique = { 
        ...xitique, 
        participants: updatedParticipants,
        transactions: updatedTx,
        status: allReceived ? XitiqueStatus.COMPLETED : (hasUnequalContributions ? XitiqueStatus.RISK : XitiqueStatus.ACTIVE)
    };

    await saveXitique(updatedXitique);

    // Mutate local state only after successful save or rely on re-fetch. 
    // For smoothness, mutating local props reference or triggering reload is needed.
    // Ideally parent should refetch, but here we update local reference for instant UI feedback.
    xitique.participants = updatedParticipants; 
    xitique.transactions = updatedTx;
    xitique.status = updatedXitique.status;
    setAiAnalysis(null);

    addToast(willReceive ? 'Pagamento registrado com sucesso' : 'Pagamento revertido', willReceive ? 'success' : 'info');
  };

  const saveBaseContributionChange = async () => {
    if (newBaseAmount <= 0) return;
    const updatedXitique = { ...xitique, amount: newBaseAmount };
    await saveXitique(updatedXitique);
    xitique.amount = newBaseAmount; 
    setIsEditingBase(false);
    addToast('Contribuição base atualizada', 'success');
  };

  const startEditingParticipant = (p: Participant) => {
      setIndividualAmount(p.customContribution !== undefined ? p.customContribution : xitique.amount);
      setEditingParticipantId(p.id);
  };

  const saveIndividualContribution = async (id: string) => {
      const updatedParticipants = xitique.participants.map(p => {
          if (p.id === id) {
              return { ...p, customContribution: individualAmount };
          }
          return p;
      });
      const updatedXitique = { 
          ...xitique, 
          participants: updatedParticipants,
          status: XitiqueStatus.RISK 
      };
      await saveXitique(updatedXitique);
      xitique.participants = updatedParticipants;
      xitique.status = XitiqueStatus.RISK;
      setEditingParticipantId(null);
      addToast('Contribuição individual atualizada', 'success');
  };

  const requestDelete = () => {
