export default XitiqueDetail;

import { supabase } from './supabase';
import { UserProfile, AuthSession } from '../types';

// Helper to map Supabase User to our App User Profile
const mapUser = (u: any): UserProfile => {
  const metadata = u.user_metadata || {};
  return {
    id: u.id,
    name: metadata.full_name || metadata.name || u.email?.split('@')[0] || 'User',
    email: u.email || '',
    photoUrl: metadata.avatar_url || metadata.picture,
    language: metadata.language || 'pt',
    lastLogin: u.last_sign_in_at || new Date().toISOString(),
    notificationPreferences: metadata.preferences || {
      contributions: true,
      payouts: true,
      updates: false
    }
  };
};

export const login = async (email: string, password: string): Promise<AuthSession> => {
  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password
  });

  if (error) throw error;
  if (!data.user || !data.session) throw new Error('No session created');

  // Mandatory Email Verification Check
  if (!data.user.email_confirmed_at) {
    await supabase.auth.signOut();
    throw new Error('EMAIL_NOT_VERIFIED');
  }

  return {
    user: mapUser(data.user),
    token: data.session.access_token
  };
};

export const loginWithGoogle = async (): Promise<void> => {
  const { error } = await supabase.auth.signInWithOAuth({
    provider: 'google',
    options: {
      redirectTo: window.location.origin
    }
  });

  if (error) throw error;
};

export const loginWithFacebook = async (): Promise<void> => {
  const { error } = await supabase.auth.signInWithOAuth({
    provider: 'facebook',
    options: {
      redirectTo: window.location.origin
    }
  });

  if (error) throw error;
};

export const register = async (name: string, email: string, password: string): Promise<AuthSession> => {
  const { data, error } = await supabase.auth.signUp({
    email,
    password,
    options: {
      data: {
        full_name: name,
        language: 'pt',
      },
      emailRedirectTo: window.location.origin
    }
  });

  if (error) throw error;

  // If email confirmation is enabled, enforce it strictly.
  if (data.user && !data.user.email_confirmed_at) {
     await supabase.auth.signOut(); // Ensure no unverified session persists
     throw new Error('CONFIRMATION_REQUIRED');
  }

  if (!data.user || !data.session) throw new Error('Registration failed');

  return {
    user: mapUser(data.user),
    token: data.session.access_token
  };
};

export const resendVerification = async (email: string): Promise<void> => {
  const { error } = await supabase.auth.resend({
    type: 'signup',
    email,
    options: {
      emailRedirectTo: window.location.origin
    }
  });
  if (error) throw error;
};

export const logout = async (): Promise<void> => {
  const { error } = await supabase.auth.signOut();
  if (error) throw error;
};

// Internal helper for Context to get current session
export const getSession = async () => {
  const { data } = await supabase.auth.getSession();
  if (data.session?.user) {
    // Enforce verification check on session retrieval
    if (!data.session.user.email_confirmed_at) {
        await supabase.auth.signOut();
        return null;
    }
    return {
       user: mapUser(data.session.user),
       token: data.session.access_token
    };
  }
  return null;
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { UserProfile } from '../types';
import { login as apiLogin, loginWithGoogle as apiLoginGoogle, loginWithFacebook as apiLoginFacebook, register as apiRegister, logout as apiLogout } from '../services/authService';
import { supabase } from '../services/supabase';
import { getUserProfile, saveUserProfile } from '../services/storage';

interface AuthContextType {
  user: UserProfile | null;
  loading: boolean;
  login: (email: string, pass: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  loginWithFacebook: () => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => Promise<void>;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  const mapAndSetUser = (u: any) => {
    const metadata = u.user_metadata || {};
    const profile: UserProfile = {
      id: u.id,
      name: metadata.full_name || metadata.name || u.email?.split('@')[0] || 'User',
      email: u.email || '',
      photoUrl: metadata.avatar_url || metadata.picture,
      language: metadata.language || 'pt',
      lastLogin: new Date().toISOString(),
      notificationPreferences: metadata.preferences || {
        contributions: true,
        payouts: true,
        updates: false
      }
    };

    // Sync with local storage for app continuity
    saveUserProfile(profile);
    setUser(profile);
    setLoading(false);
  };

  // Initialize Supabase Auth Listener
  useEffect(() => {
    // 1. Check active session
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      if (session?.user) {
        if (!session.user.email_confirmed_at) {
            await supabase.auth.signOut();
            setLoading(false);
        } else {
            mapAndSetUser(session.user);
        }
      } else {
        setLoading(false);
      }
    });

    // 2. Listen for changes (login, logout, token refresh)
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (session?.user) {
        if (!session.user.email_confirmed_at) {
            // If user logs in but isn't verified (e.g. via strict session restoration)
            await supabase.auth.signOut();
            setUser(null);
            setLoading(false);
        } else {
            mapAndSetUser(session.user);
        }
      } else {
        setUser(null);
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const login = async (email: string, pass: string) => {
    await apiLogin(email, pass);
    // State update handled by onAuthStateChange
  };

  const loginWithGoogle = async () => {
    await apiLoginGoogle();
    // Redirects away
  };

  const loginWithFacebook = async () => {
    await apiLoginFacebook();
    // Redirects away
  };

  const register = async (name: string, email: string, pass: string) => {
    await apiRegister(name, email, pass);
    // State update handled by onAuthStateChange
  };

  const logout = async () => {
    await apiLogout();
    // State update handled by onAuthStateChange
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      loading, 
      login, 
      loginWithGoogle,
      loginWithFacebook,
      register, 
      logout,
      isAuthenticated: !!user 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
